{
  "name": "MedCareAlert+",
  "description": "An AI-powered platform for medication tracking and pharmacy availability in Tunisia. Features prescription OCR, automated reminders, and geolocation-based pharmacy search.",
  "requestFramePermissions": [
    "camera",
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  PATIENT = 'PATIENT',
  PHARMACIST = 'PHARMACIST',
  ADMIN = 'ADMIN'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  location?: {
    lat: number;
    lng: number;
  };
}

export interface Medication {
  id: string;
  userId: string;
  name: string;
  dosage: string;
  frequency: string;
  durationInDays: number;
  startDate: string;
  stockCount: number;
  threshold: number;
  takenToday?: boolean;
}

export interface Pharmacy {
  id: string;
  name: string;
  address: string;
  location: {
    lat: number;
    lng: number;
  };
  phone: string;
  stockStatus: 'available' | 'low' | 'out_of_stock';
  distance?: number;
}

export interface ScanResult {
  medications: Array<{
    name: string;
    dosage: string;
    frequency: string;
    durationInDays: number;
  }>;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ScanResult } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const scanPrescription = async (base64Image: string): Promise<ScanResult> => {
  const model = 'gemini-3-flash-preview';

  const prompt = "Analyze this medical prescription image and extract the medication list. For each medication, identify its name, dosage (e.g., 500mg), frequency (e.g., twice a day), and duration in days (if mentioned, otherwise default to 7). Return strictly valid JSON.";

  const response = await ai.models.generateContent({
    model: model,
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          medications: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                dosage: { type: Type.STRING },
                frequency: { type: Type.STRING },
                durationInDays: { type: Type.NUMBER }
              },
              required: ["name", "dosage", "frequency", "durationInDays"]
            }
          }
        },
        required: ["medications"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{"medications": []}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return { medications: [] };
  }
};

import React, { useState, useEffect } from 'react';
import { User, UserRole, Medication, Pharmacy } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PharmacyMap from './components/PharmacyMap';
import InventoryManager from './components/InventoryManager';
import Auth from './components/Auth';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'dashboard' | 'map' | 'inventory' | 'profile'>('dashboard');

  // Local state to simulate DB
  const [medications, setMedications] = useState<Medication[]>([]);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);

  useEffect(() => {
    // Initial data load
    const mockPharmacies: Pharmacy[] = [
      { id: '1', name: 'Pharmacie de la Marsa', address: 'Av. Habib Bourguiba, La Marsa', location: { lat: 36.878, lng: 10.334 }, phone: '+216 71 000 001', stockStatus: 'available' },
      { id: '2', name: 'Pharmacie Centrale Tunis', address: 'Rue de Rome, Tunis', location: { lat: 36.806, lng: 10.181 }, phone: '+216 71 000 002', stockStatus: 'low' },
      { id: '3', name: 'Pharmacie Ennasr', address: 'Avenue Hédi Nouira, Ariana', location: { lat: 36.858, lng: 10.158 }, phone: '+216 71 000 003', stockStatus: 'out_of_stock' },
    ];
    setPharmacies(mockPharmacies);

    // Check local storage for user
    const savedUser = localStorage.getItem('medcare_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('medcare_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('medcare_user');
  };

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <Layout 
      user={user} 
      currentView={view} 
      onViewChange={setView} 
      onLogout={handleLogout}
    >
      {view === 'dashboard' && <Dashboard user={user} medications={medications} setMedications={setMedications} />}
      {view === 'map' && <PharmacyMap pharmacies={pharmacies} />}
      {view === 'inventory' && user.role === UserRole.PHARMACIST && <InventoryManager />}
      {view === 'profile' && (
        <div className="p-6 bg-white rounded-xl shadow-sm border border-slate-200">
          <h2 className="text-2xl font-bold mb-4">User Profile</h2>
          <div className="space-y-4">
            <p><strong>Name:</strong> {user.name}</p>
            <p><strong>Email:</strong> {user.email}</p>
            <p><strong>Role:</strong> {user.role}</p>
            <button 
              onClick={handleLogout}
              className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition"
            >
              Sign Out
            </button>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React from 'react';
