);

export default Layout;

import React, { useState } from 'react';
import { User, Medication } from '../types';
import PrescriptionScanner from './PrescriptionScanner';

interface DashboardProps {
  user: User;
  medications: Medication[];
  setMedications: React.Dispatch<React.SetStateAction<Medication[]>>;
}

const Dashboard: React.FC<DashboardProps> = ({ medications, setMedications }) => {
  const [showScanner, setShowScanner] = useState(false);

  const toggleMedication = (id: string) => {
    setMedications(prev => prev.map(m => 
      m.id === id ? { ...m, takenToday: !m.takenToday } : m
    ));
  };

  const handleScanComplete = (newMeds: Array<Partial<Medication>>) => {
    const formatted: Medication[] = newMeds.map((m, idx) => ({
      id: Math.random().toString(36).substr(2, 9),
      userId: '1',
      name: m.name || 'Unknown',
      dosage: m.dosage || '1 unit',
      frequency: m.frequency || '1x daily',
      durationInDays: m.durationInDays || 7,
      startDate: new Date().toISOString(),
      stockCount: 30,
      threshold: 5,
      takenToday: false
    }));
    setMedications(prev => [...prev, ...formatted]);
    setShowScanner(false);
  };

  const progress = medications.length > 0 
    ? Math.round((medications.filter(m => m.takenToday).length / medications.length) * 100) 
    : 0;

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Adherence Card */}
        <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-6 rounded-2xl shadow-lg text-white">
          <h3 className="text-lg font-semibold mb-2">Today's Progress</h3>
          <div className="flex items-end justify-between mb-4">
            <span className="text-4xl font-bold">{progress}%</span>
            <span className="text-blue-100">{medications.filter(m => m.takenToday).length} / {medications.length} doses</span>
          </div>
          <div className="w-full bg-blue-400/30 rounded-full h-3">
            <div className="bg-white h-full rounded-full transition-all duration-1000" style={{ width: `${progress}%` }}></div>
          </div>
          <p className="mt-4 text-sm text-blue-100">Maintain high adherence to recover faster!</p>
        </div>

        {/* Action Card */}
        <div 
          onClick={() => setShowScanner(true)}
          className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 cursor-pointer hover:border-blue-300 hover:shadow-md transition-all group"
        >
          <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center mb-4 group-hover:bg-emerald-100 transition">
            <i className="fas fa-camera text-xl"></i>
          </div>
          <h3 className="text-lg font-bold text-slate-800">Scan Prescription</h3>
          <p className="text-slate-500 text-sm">Upload a photo to automatically add your medications using AI.</p>
        </div>

        {/* Alert Card */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="w-12 h-12 bg-amber-50 text-amber-600 rounded-full flex items-center justify-center mb-4">
            <i className="fas fa-triangle-exclamation text-xl"></i>
          </div>
          <h3 className="text-lg font-bold text-slate-800">Supply Alerts</h3>
          <p className="text-slate-500 text-sm">You have {medications.filter(m => m.stockCount < m.threshold).length} medications running low.</p>
        </div>
      </div>

      {/* Medication List */}
      <section>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-bold text-slate-800">Today's Schedule</h2>
          <button className="text-blue-600 font-medium hover:underline text-sm">View Calendar</button>
        </div>

        <div className="space-y-4">
          {medications.length === 0 ? (
            <div className="text-center py-12 bg-white rounded-2xl border-2 border-dashed border-slate-200">
              <i className="fas fa-pills text-slate-300 text-4xl mb-4"></i>
              <p className="text-slate-400">No medications added yet. Use the scan feature!</p>
            </div>
          ) : (
            medications.map(med => (
              <div 
                key={med.id} 
                className={`bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex items-center gap-4 transition-all ${med.takenToday ? 'opacity-60 bg-slate-50' : ''}`}
              >
                <button 
                  onClick={() => toggleMedication(med.id)}
                  className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border-2 ${
                    med.takenToday 
                      ? 'bg-blue-600 border-blue-600 text-white' 
                      : 'border-slate-200 text-slate-300 hover:border-blue-400'
                  }`}
                >
                  <i className="fas fa-check"></i>
                </button>
                <div className="flex-1">
                  <h4 className={`font-bold ${med.takenToday ? 'line-through text-slate-500' : 'text-slate-800'}`}>
                    {med.name}
                  </h4>
                  <p className="text-sm text-slate-500">{med.dosage} • {med.frequency}</p>
                </div>
                <div className="text-right">
                  <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                    med.stockCount < med.threshold ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-600'
                  }`}>
                    {med.stockCount} left
                  </span>
                  <p className="text-xs text-slate-400 mt-1">{med.durationInDays} days duration</p>
                </div>
              </div>
            ))
          )}
        </div>
      </section>

      {showScanner && (
        <PrescriptionScanner 
          onClose={() => setShowScanner(false)} 
          onComplete={handleScanComplete} 
        />
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef } from 'react';
import { scanPrescription } from '../geminiService';

interface PrescriptionScannerProps {
  onClose: () => void;
  onComplete: (meds: any[]) => void;
}

const PrescriptionScanner: React.FC<PrescriptionScannerProps> = ({ onClose, onComplete }) => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setImage(reader.result as string);
        processImage(base64String);
      };
      reader.readAsDataURL(file);
    }
  };

  const processImage = async (base64: string) => {
    setIsProcessing(true);
    setError(null);
    try {
      const result = await scanPrescription(base64);
      if (result.medications.length > 0) {
        onComplete(result.medications);
      } else {
        setError("AI couldn't find any medications. Try a clearer photo.");
      }
    } catch (err) {
      setError("Analysis failed. Please try again.");
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl overflow-hidden relative">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 p-2 rounded-full hover:bg-slate-100 transition"
        >
          <i className="fas fa-times text-xl"></i>
        </button>

        <div className="p-8">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
              <i className="fas fa-prescription-bottle-medical text-3xl"></i>
            </div>
            <h2 className="text-2xl font-bold text-slate-800">AI Prescription Scan</h2>
            <p className="text-slate-500">Fast tracking powered by Gemini 3</p>
          </div>

          {!image ? (
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group"
            >
              <i className="fas fa-cloud-arrow-up text-4xl text-slate-300 group-hover:text-blue-500 mb-4 transition"></i>
              <p className="font-medium text-slate-700">Choose a photo or capture now</p>
              <p className="text-sm text-slate-400 mt-1">Supports JPEG, PNG up to 10MB</p>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept="image/*" 
              />
            </div>
          ) : (
            <div className="space-y-6">
              <div className="relative rounded-xl overflow-hidden aspect-video border border-slate-200">
                <img src={image} alt="Prescription" className="w-full h-full object-cover" />
                {isProcessing && (
                  <div className="absolute inset-0 bg-slate-900/50 flex flex-col items-center justify-center text-white p-4">
                    <div className="w-10 h-10 border-4 border-white/30 border-t-white rounded-full animate-spin mb-4"></div>
                    <p className="font-medium">Gemini is reading your prescription...</p>
                    <p className="text-xs text-white/70 mt-1">This takes a few seconds</p>
                  </div>
                )}
              </div>

              {error && (
                <div className="p-4 bg-red-50 text-red-700 rounded-xl flex gap-3 items-center">
                  <i className="fas fa-circle-exclamation"></i>
                  <p className="text-sm">{error}</p>
                </div>
              )}

              <button 
                onClick={() => setImage(null)}
                className="w-full py-3 text-slate-600 font-medium hover:bg-slate-50 rounded-xl transition"
                disabled={isProcessing}
              >
                Choose different photo
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default PrescriptionScanner;

import React, { useState, useEffect } from 'react';
import { Pharmacy } from '../types';

interface PharmacyMapProps {
  pharmacies: Pharmacy[];
}

const PharmacyMap: React.FC<PharmacyMapProps> = ({ pharmacies }) => {
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => console.warn("Geolocation denied", err)
      );
    }
  }, []);

  const filteredPharmacies = pharmacies.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    p.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="h-full space-y-6">
      <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4">
        <div className="flex-1 relative">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
          <input 
            type="text" 
            placeholder="Search by pharmacy name or city..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
          />
        </div>
        <button className="px-6 py-3 bg-blue-600 text-white font-medium rounded-xl hover:bg-blue-700 transition flex items-center justify-center gap-2">
          <i className="fas fa-location-crosshairs"></i>
          Find Near Me
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-320px)]">
        {/* Pharmacy List */}
        <div className="lg:col-span-4 space-y-4 overflow-y-auto pr-2">
          {filteredPharmacies.map(pharmacy => (
            <div 
              key={pharmacy.id}
              className="bg-white p-4 rounded-xl border border-slate-200 hover:border-blue-300 hover:shadow-md transition-all cursor-pointer group"
            >
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-bold text-slate-800 group-hover:text-blue-700 transition">{pharmacy.name}</h3>
                <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded-full ${
                  pharmacy.stockStatus === 'available' ? 'bg-emerald-100 text-emerald-700' :
                  pharmacy.stockStatus === 'low' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                }`}>
                  {pharmacy.stockStatus.replace('_', ' ')}
                </span>
              </div>
              <p className="text-sm text-slate-500 flex items-start gap-2 mb-3">
                <i className="fas fa-map-marker-alt mt-1 text-slate-400"></i>
                {pharmacy.address}
              </p>
              <div className="flex gap-2">
                <a href={`tel:${pharmacy.phone}`} className="flex-1 py-2 text-center text-blue-600 bg-blue-50 rounded-lg text-xs font-bold hover:bg-blue-100 transition">
                  <i className="fas fa-phone mr-2"></i> CALL
                </a>
                <button className="flex-1 py-2 text-center text-slate-600 bg-slate-100 rounded-lg text-xs font-bold hover:bg-slate-200 transition">
                  <i className="fas fa-route mr-2"></i> GO
                </button>
              </div>
            </div>
          ))}
        </div>

        {/* Map Placeholder */}
        <div className="lg:col-span-8 bg-slate-200 rounded-2xl relative overflow-hidden">
          <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 bg-[url('https://picsum.photos/1200/800?grayscale')] bg-cover bg-center">
             <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-[1px]"></div>
             <div className="relative z-10 bg-white/90 p-6 rounded-2xl shadow-xl text-center max-w-sm">
               <i className="fas fa-map-pin text-4xl text-red-500 mb-4 animate-bounce"></i>
               <h4 className="text-lg font-bold text-slate-800 mb-2">Interactive Map</h4>
               <p className="text-sm text-slate-600">Showing {filteredPharmacies.length} pharmacies in Tunisia. Geolocation active.</p>
               {userLocation && <p className="text-xs text-blue-600 mt-2">Lat: {userLocation.lat.toFixed(4)}, Lng: {userLocation.lng.toFixed(4)}</p>}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PharmacyMap;

import React, { useState } from 'react';
import { User, UserRole } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

