}

import { GoogleGenAI, Type } from "@google/genai";
import { ScanResult } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const scanPrescription = async (base64Image: string): Promise<ScanResult> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this medical prescription image and extract the medication list. 
  For each medication, identify:
  1. name (e.g., Doliprane)
  2. dosage (e.g., 1000mg)
  3. frequency (e.g., 3 times per day)
  4. durationInDays (default to 7 if not specified)
  5. suggestedSchedules: An array of 24h format times based on frequency (e.g., if 3 times, suggest ["08:00", "14:00", "20:00"]).

  Return strictly valid JSON.`;

  const response = await ai.models.generateContent({
    model: model,
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          medications: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                dosage: { type: Type.STRING },
                frequency: { type: Type.STRING },
                durationInDays: { type: Type.NUMBER },
                suggestedSchedules: { 
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                }
              },
              required: ["name", "dosage", "frequency", "durationInDays", "suggestedSchedules"]
            }
          }
        },
        required: ["medications"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{"medications": []}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return { medications: [] };
  }
};

import React, { useState, useEffect } from 'react';
import { User, UserRole, Medication, Pharmacy } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PharmacyMap from './components/PharmacyMap';
import InventoryManager from './components/InventoryManager';
import HistoryView from './components/HistoryView';
import Auth from './components/Auth';
import NotificationProvider from './components/NotificationProvider';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'dashboard' | 'map' | 'inventory' | 'profile' | 'history'>('dashboard');

  const [medications, setMedications] = useState<Medication[]>([]);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);

  useEffect(() => {
    const mockPharmacies: Pharmacy[] = [
      { id: '1', name: 'Pharmacie de la Marsa', address: 'Av. Habib Bourguiba, La Marsa', location: { lat: 36.878, lng: 10.334 }, phone: '+216 71 000 001', stockStatus: 'available' },
      { id: '2', name: 'Pharmacie Centrale Tunis', address: 'Rue de Rome, Tunis', location: { lat: 36.806, lng: 10.181 }, phone: '+216 71 000 002', stockStatus: 'low' },
      { id: '3', name: 'Pharmacie Ennasr', address: 'Avenue Hédi Nouira, Ariana', location: { lat: 36.858, lng: 10.158 }, phone: '+216 71 000 003', stockStatus: 'out_of_stock' },
    ];
    setPharmacies(mockPharmacies);

    const savedUser = localStorage.getItem('medcare_user');
    const savedMeds = localStorage.getItem('medcare_meds');

    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedMeds) setMedications(JSON.parse(savedMeds));
  }, []);

  useEffect(() => {
    if (medications.length > 0) {
      localStorage.setItem('medcare_meds', JSON.stringify(medications));
    }
  }, [medications]);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('medcare_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('medcare_user');
    localStorage.removeItem('medcare_meds');
    setMedications([]);
  };

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <NotificationProvider medications={medications}>
      <Layout 
        user={user} 
        currentView={view} 
        onViewChange={setView} 
        onLogout={handleLogout}
      >
        {view === 'dashboard' && <Dashboard user={user} medications={medications} setMedications={setMedications} />}
        {view === 'map' && <PharmacyMap pharmacies={pharmacies} />}
        {view === 'history' && <HistoryView medications={medications} />}
        {view === 'inventory' && user.role === UserRole.PHARMACIST && <InventoryManager />}
        {view === 'profile' && (
          <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-2xl font-bold mb-4">User Profile</h2>
            <div className="space-y-6">
              <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-xl">
                <div className="w-16 h-16 rounded-full bg-blue-600 flex items-center justify-center text-white text-2xl font-bold">
                  {user.name[0]}
                </div>
                <div>
                  <h3 className="text-xl font-bold text-slate-800">{user.name}</h3>
                  <p className="text-slate-500">{user.email}</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 border border-slate-100 rounded-xl">
                  <span className="text-xs text-slate-400 block uppercase font-bold mb-1">Role</span>
                  <span className="font-semibold text-slate-700">{user.role}</span>
                </div>
                <div className="p-4 border border-slate-100 rounded-xl">
                  <span className="text-xs text-slate-400 block uppercase font-bold mb-1">Meds Tracked</span>
                  <span className="font-semibold text-slate-700">{medications.length}</span>
                </div>
              </div>
              <button 
                onClick={handleLogout}
                className="w-full px-4 py-3 bg-red-50 text-red-600 font-bold rounded-xl hover:bg-red-100 transition border border-red-100"
              >
                Sign Out
              </button>
            </div>
          </div>
        )}
      </Layout>
    </NotificationProvider>
  );
};

export default App;

