interface NotificationProviderProps {
  children: React.ReactNode;
  medications: Medication[];
}

const NotificationProvider: React.FC<NotificationProviderProps> = ({ children, medications }) => {
  const [activeAlert, setActiveAlert] = useState<string | null>(null);

  useEffect(() => {
    const interval = setInterval(() => {
      const now = new Date();
      const currentTime = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false });

      medications.forEach(med => {
        if (med.schedules.includes(currentTime)) {
          // In a real app, we'd use navigator.serviceWorker or standard Notification API
          setActiveAlert(`Time to take your ${med.name} (${med.dosage})!`);
          setTimeout(() => setActiveAlert(null), 10000); // Hide after 10s
        }
      });
    }, 60000); // Check every minute

    return () => clearInterval(interval);
  }, [medications]);

  return (
    <>
      {activeAlert && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md p-4 animate-in slide-in-from-top duration-500">
          <div className="bg-slate-900 text-white p-6 rounded-[2rem] shadow-2xl flex items-center gap-5 border border-white/10 backdrop-blur-xl">
            <div className="w-12 h-12 bg-blue-500 rounded-full flex items-center justify-center animate-bounce">
              <i className="fas fa-bell"></i>
            </div>
            <div className="flex-1">
              <h4 className="font-black text-blue-400 uppercase text-xs tracking-widest mb-1">Medication Reminder</h4>
              <p className="font-bold">{activeAlert}</p>
            </div>
            <button onClick={() => setActiveAlert(null)} className="text-slate-400 hover:text-white">
              <i className="fas fa-times"></i>
            </button>
          </div>
        </div>
      )}
      {children}
    </>
  );
};

