import { GoogleGenAI, Type } from "@google/genai";
import { ScanResult } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const scanPrescription = async (base64Image: string): Promise<ScanResult> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `Analyze this medical prescription image and extract the medication list. 
  For each medication, identify:
  1. name (e.g., Doliprane)
  2. dosage (e.g., 1000mg)
  3. frequency (e.g., 3 times per day)
  4. durationInDays (default to 7 if not specified)
  5. suggestedSchedules: An array of 24h format times based on frequency (e.g., if 3 times, suggest ["08:00", "14:00", "20:00"]).

  Return strictly valid JSON.`;

  const response = await ai.models.generateContent({
    model: model,
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          medications: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                dosage: { type: Type.STRING },
                frequency: { type: Type.STRING },
                durationInDays: { type: Type.NUMBER },
                suggestedSchedules: { 
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                }
              },
              required: ["name", "dosage", "frequency", "durationInDays", "suggestedSchedules"]
            }
          }
        },
        required: ["medications"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{"medications": []}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return { medications: [] };
  }
};

export const findNearbyPharmacies = async (lat: number, lng: number, query: string = "pharmacies") => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `List active and nearby ${query} around my location in Tunisia. Provide names, approximate locations, and status if available.`,
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: {
            latitude: lat,
            longitude: lng
          }
        }
      }
    },
  });

  return {
    text: response.text,
    grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
  };
};

