import mongoose, { Schema } from 'mongoose';

// USER SCHEMA
const UserSchema = new Schema({
  name: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  password: { type: String, required: true },
  role: { type: String, enum: ['PATIENT', 'PHARMACIST', 'ADMIN'], default: 'PATIENT' },
  fcmToken: { type: String }, // For real push notifications (Firebase/WebPush)
  location: {
    lat: Number,
    lng: Number
  }
}, { timestamps: true });

// MEDICATION SCHEMA
const MedicationSchema = new Schema({
  userId: { type: Schema.Types.ObjectId, ref: 'User', required: true },
  name: { type: String, required: true },
  dosage: String,
  frequency: String,
  durationInDays: Number,
  startDate: { type: Date, default: Date.now },
  stockCount: { type: Number, default: 30 },
  threshold: { type: Number, default: 5 }, // "Alerte avant rupture"
  schedules: [{ type: String }], // e.g., ["08:00", "20:00"]
  isActive: { type: Boolean, default: true }
}, { timestamps: true });

// NOTIFICATION LOG (To prevent duplicate alerts)
const NotificationSchema = new Schema({
  userId: { type: Schema.Types.ObjectId, ref: 'User', required: true },
  medicationId: { type: Schema.Types.ObjectId, ref: 'Medication' },
  type: { type: String, enum: ['REMINDER', 'STOCK_ALERT'] },
  sentAt: { type: Date, default: Date.now }
});

export const UserModel = mongoose.model('User', UserSchema);
export const MedicationModel = mongoose.model('Medication', MedicationSchema);
export const NotificationModel = mongoose.model('Notification', NotificationSchema);

import express from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import { MedicationModel, NotificationModel } from './models';

const app = express();
app.use(express.json());
app.use(cors());

// --- MEDICATION MANAGEMENT ---

// Fetch all patient medications
app.get('/api/medications', async (req, res) => {
  try {
    const userId = req.headers['user-id']; // Simplified auth for example
    const meds = await MedicationModel.find({ userId, isActive: true });
    res.json(meds);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Update stock after taking med
app.patch('/api/medications/:id/take', async (req, res) => {
  try {
    const med = await MedicationModel.findById(req.params.id);
    if (!med) return res.status(404).send('Not found');

    med.stockCount = Math.max(0, med.stockCount - 1);
    await med.save();

    // Check for stock rupture alert
    if (med.stockCount <= med.threshold) {
      // Logic to trigger real Push Notification via FCM/WebPush would go here
      console.log(`ALERT: ${med.name} is running low (${med.stockCount} left)`);

      await NotificationModel.create({
        userId: med.userId,
        medicationId: med.id,
        type: 'STOCK_ALERT'
      });
    }

    res.json(med);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// --- ALERT SYSTEM ---

// Endpoint for the app to poll for active alerts (or used for WebSockets)
app.get('/api/alerts/stock', async (req, res) => {
  try {
    const userId = req.headers['user-id'];
    const lowStockMeds = await MedicationModel.find({
      userId,
      isActive: true,
      $expr: { $lte: ["$stockCount", "$threshold"] }
    });
    res.json(lowStockMeds);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

