               <i className="fas fa-plus text-xs"></i>
             </button>
          </div>
          <div className="flex gap-2">
             <span className="px-3 py-1 bg-white border border-slate-200 rounded-full text-xs font-bold text-slate-500 uppercase">
               Active: {medications.length}
             </span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {medications.length === 0 ? (
            <div className="col-span-full text-center py-20 bg-white rounded-[3rem] border-2 border-dashed border-slate-200">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                 <i className="fas fa-pills text-4xl"></i>
              </div>
              <h3 className="text-xl font-bold text-slate-800 mb-2">No medications found</h3>
              <p className="text-slate-400 max-w-xs mx-auto">Start by scanning a prescription or adding your pills manually.</p>
