            medications.map(med => (
              <div 
                key={med.id} 
                className={`bg-white p-7 rounded-[2.5rem] shadow-sm border flex flex-col gap-6 transition-all duration-300 ${
                  med.stockCount <= med.threshold ? 'border-red-200 shadow-red-50' : 'border-slate-100'
