                  </div>
                  <div className="text-right">
                    <span className={`text-[10px] px-3 py-1 rounded-full font-black uppercase tracking-wider ${
                      med.stockCount <= med.threshold ? 'bg-red-600 text-white animate-bounce' : 'bg-slate-50 text-slate-400'
                    }`}>
                      {med.stockCount} LEFT
                    </span>
                  </div>
                </div>

                <div>
                  <h4 className="text-xl font-black text-slate-900 leading-tight mb-1">{med.name}</h4>
                  <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">{med.dosage} • {med.frequency}</p>
                </div>

                <div className="space-y-3">
                  <div className="flex items-center gap-2 flex-wrap">
                    {med.schedules.map((time, idx) => (
                      <span key={idx} className="px-3 py-1.5 bg-slate-50 text-slate-600 text-xs font-bold rounded-lg border border-slate-100">
                        {time}
                      </span>
                    ))}
                  </div>
                  <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                    <div 
                      className="bg-emerald-500 h-full rounded-full transition-all"
                      style={{ width: `${(med.takenTodayCount / med.schedules.length) * 100}%` }}
                    ></div>
                  </div>
                </div>

                <button 
                  onClick={() => handleTakeMedication(med.id)}
                  disabled={med.takenTodayCount >= med.schedules.length || med.stockCount === 0}
                  className={`w-full py-4 rounded-2xl font-black transition-all ${
                    med.stockCount === 0 
                      ? 'bg-red-50 text-red-400 cursor-not-allowed border border-red-100'
                      : med.takenTodayCount >= med.schedules.length
