        />
      )}

      {showAddModal && (
        <MedicationModal 
          onClose={() => setShowAddModal(false)}
          onSave={handleAddMedication}
        />
      )}
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState, useCallback, useRef } from 'react';
import { Medication } from '../types';

interface NotificationProviderProps {
  children: React.ReactNode;
  medications: Medication[];
}

interface ActiveAlert {
  id: string;
  type: 'REMINDER' | 'STOCK';
  message: string;
  medName: string;
}

const NotificationProvider: React.FC<NotificationProviderProps> = ({ children, medications }) => {
  const [activeAlerts, setActiveAlerts] = useState<ActiveAlert[]>([]);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const hasWelcomed = useRef(false);

  // Request browser notification permission on mount
  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
      if (Notification.permission === 'default') {
        Notification.requestPermission().then(setPermission);
      }
    }
  }, []);

  // Helper to trigger a real system notification (Web Push style)
  const sendSystemNotification = useCallback((title: string, body: string, iconType: 'STOCK' | 'REMINDER' | 'SYSTEM') => {
    if ('Notification' in window && Notification.permission === 'granted') {
      const icon = iconType === 'STOCK' 
        ? 'https://cdn-icons-png.flaticon.com/512/595/595067.png' 
        : iconType === 'REMINDER'
          ? 'https://cdn-icons-png.flaticon.com/512/3119/3119338.png'
          : 'https://cdn-icons-png.flaticon.com/512/190/190411.png';

      new Notification(title, {
        body,
        icon,
        badge: icon,
        vibrate: [200, 100, 200],
        tag: title 
      } as any);
    }
  }, []);

  const addAlert = useCallback((alert: Omit<ActiveAlert, 'id'>) => {
    const id = Math.random().toString(36).substr(2, 9);
    setActiveAlerts(prev => [...prev, { ...alert, id }]);

    // Trigger the real OS-level notification
    const title = alert.type === 'STOCK' ? '⚠️ Stock Alert: ' + alert.medName : '💊 Med Reminder: ' + alert.medName;
    sendSystemNotification(title, alert.message, alert.type);

    // Auto-dismiss the UI toast after 8 seconds
    setTimeout(() => {
      setActiveAlerts(prev => prev.filter(a => a.id !== id));
    }, 8000);
  }, [sendSystemNotification]);

  // Welcome Alert to confirm setup
  useEffect(() => {
    if (permission === 'granted' && !hasWelcomed.current) {
      addAlert({
        type: 'REMINDER',
        medName: 'MedCare+',
        message: 'System alerts are active! We will notify you for your doses.'
      });
      hasWelcomed.current = true;
    }
  }, [permission, addAlert]);

  // Check for intake reminders every 30 seconds for better accuracy
  useEffect(() => {
    const checkReminders = () => {
      const now = new Date();
      // Ensure fixed HH:mm format
      const currentTime = now.getHours().toString().padStart(2, '0') + ':' + now.getMinutes().toString().padStart(2, '0');

      medications.forEach(med => {
        if (med.schedules.includes(currentTime)) {
          // Check if already reminded in the last 60s to avoid double-alerts
          const alertExists = activeAlerts.find(a => a.medName === med.name && a.type === 'REMINDER');
          if (!alertExists) {
            addAlert({
              type: 'REMINDER',
              medName: med.name,
              message: `Time for your scheduled dose of ${med.name} (${med.dosage}).`
            });
          }
        }
      });
    };

    const interval = setInterval(checkReminders, 30000);
    return () => clearInterval(interval);
  }, [medications, addAlert, activeAlerts]);

  // Check for stock alerts whenever medications change
  useEffect(() => {
    medications.forEach(med => {
      if (med.stockCount > 0 && med.stockCount <= med.threshold) {
        const alertExists = activeAlerts.find(a => a.type === 'STOCK' && a.medName === med.name && a.message.includes('low'));
        if (!alertExists) {
          addAlert({
            type: 'STOCK',
            medName: med.name,
            message: `Critical: ${med.name} stock is low (${med.stockCount} left). Please restock soon!`
          });
        }
      } else if (med.stockCount === 0 && med.id !== 'test-id') {
        const alertExists = activeAlerts.find(a => a.type === 'STOCK' && a.medName === med.name && a.message.includes('run out'));
        if (!alertExists) {
          addAlert({
            type: 'STOCK',
            medName: med.name,
            message: `Rupture: You have run out of ${med.name}!`
          });
        }
      }
      // Special handling for the manual "Test Alert" logic
      if (med.id === 'test-id' && med.stockCount === 0) {
        const alertExists = activeAlerts.find(a => a.medName === 'Test Vitamin');
        if (!alertExists) {
          addAlert({
            type: 'STOCK',
            medName: 'Test Vitamin',
            message: `Rupture: You have run out of Test Vitamin!`
          });
        }
      }
    });
  }, [medications, addAlert]);

  return (
    <>
      {/* Toast Notification Layer */}
      <div className="fixed top-6 right-6 z-[100] w-full max-sm space-y-4 pointer-events-none">
        {activeAlerts.map((alert) => (
          <div 
            key={alert.id}
            className={`pointer-events-auto w-full p-5 rounded-[2rem] shadow-2xl border backdrop-blur-xl animate-in slide-in-from-right duration-500 ${
              alert.type === 'STOCK' 
                ? 'bg-red-600 border-red-500 text-white' 
                : 'bg-slate-900 border-white/10 text-white'
            }`}
          >
            <div className="flex items-start gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shrink-0 ${
                alert.type === 'STOCK' ? 'bg-white/20' : 'bg-blue-500'
              }`}>
                <i className={`fas ${alert.type === 'STOCK' ? 'fa-triangle-exclamation' : 'fa-bell'} text-xl`}></i>
              </div>
              <div className="flex-1">
                <div className="flex justify-between items-start">
                  <h4 className="font-black uppercase text-[10px] tracking-widest opacity-70 mb-1">
                    {alert.type === 'STOCK' ? 'Stock Warning' : 'Medication Reminder'}
                  </h4>
                  <button onClick={() => setActiveAlerts(prev => prev.filter(a => a.id !== alert.id))}>
                    <i className="fas fa-times text-xs opacity-50 hover:opacity-100"></i>
                  </button>
                </div>
                <p className="font-bold leading-tight">{alert.message}</p>
                {alert.type === 'STOCK' && alert.medName !== 'Test Vitamin' && (
                  <button className="mt-3 px-4 py-1.5 bg-white text-red-600 text-[10px] font-black rounded-full hover:bg-slate-100 transition">
                    FIND NEAREST PHARMACY
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}

        {/* Permission Request helper (mini) */}
        {permission === 'default' && (
          <div className="pointer-events-auto bg-white border-2 border-blue-500 p-6 rounded-[2rem] shadow-2xl flex flex-col gap-4 animate-in slide-in-from-bottom duration-700">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-200">
                <i className="fas fa-shield-halved text-2xl"></i>
              </div>
              <div className="flex-1">
                <p className="text-sm font-black text-slate-800 uppercase tracking-widest">Enable Alerts</p>
                <p className="text-xs font-medium text-slate-500">Allow system-level reminders even when the app is minimized.</p>
              </div>
            </div>
            <button 
              onClick={() => Notification.requestPermission().then(setPermission)}
              className="w-full py-3 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 transition shadow-lg shadow-blue-100"
            >
              GRANT PERMISSION
            </button>
          </div>
        )}
      </div>
      {children}
    </>
  );
};

export default NotificationProvider;

import express from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import { MedicationModel, NotificationModel } from './models';

const app = express();
// Add 'as any' to avoid type mismatch between different versions of Express/Body-parser middleware types
app.use(express.json() as any);
// Fix: Use any to avoid type mismatch between different versions of Express/Cors middleware types
app.use(cors() as any);

// --- MEDICATION MANAGEMENT ---

// Fetch all patient medications
app.get('/api/medications', async (req, res) => {
  try {
    const userId = req.headers['user-id']; // Simplified auth for example
    const meds = await MedicationModel.find({ userId, isActive: true });
    res.json(meds);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Update stock after taking med
app.patch('/api/medications/:id/take', async (req, res) => {
  try {
    const med = await MedicationModel.findById(req.params.id);
    if (!med) return res.status(404).send('Not found');

    med.stockCount = Math.max(0, med.stockCount - 1);
    await med.save();

    // Check for stock rupture alert
    if (med.stockCount <= med.threshold) {
      // Logic to trigger real Push Notification via FCM/WebPush would go here
      console.log(`ALERT: ${med.name} is running low (${med.stockCount} left)`);

      await NotificationModel.create({
        userId: med.userId,
        medicationId: med.id,
        type: 'STOCK_ALERT'
      });
    }

    res.json(med);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// --- ALERT SYSTEM ---

// Endpoint for the app to poll for active alerts (or used for WebSockets)
app.get('/api/alerts/stock', async (req, res) => {
  try {
    const userId = req.headers['user-id'];
    const lowStockMeds = await MedicationModel.find({
      userId,
      isActive: true,
      $expr: { $lte: ["$stockCount", "$threshold"] }
    });
    res.json(lowStockMeds);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

const PORT = process.env.PORT || 5000;
mongoose.connect(process.env.MONGODB_URI || 'mongodb://localhost:27017/medcare')
  .then(() => app.listen(PORT, () => console.log(`Server running on port ${PORT}`)))
  .catch(err => console.error(err));

export enum UserRole {
  PATIENT = 'PATIENT',
  PHARMACIST = 'PHARMACIST',
  ADMIN = 'ADMIN'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  location?: {
    lat: number;
    lng: number;
  };
}

export interface MedicationHistory {
  date: string;
  time: string;
  status: 'taken' | 'missed';
}

export interface Medication {
  id: string;
  userId: string;
  name: string;
  dosage: string;
  frequency: string;
  durationInDays: number;
  startDate: string;
  stockCount: number;
  threshold: number;
  schedules: string[]; // e.g., ["08:00", "20:00"]
  history: MedicationHistory[];
  takenTodayCount: number;
}

export interface Pharmacy {
  id: string;
  name: string;
  address: string;
  location: {
    lat: number;
    lng: number;
  };
  phone: string;
  stockStatus: 'available' | 'low' | 'out_of_stock';
  distance?: number;
  services: string[]; // e.g., ["24/7", "Vaccinations", "Delivery"]
}

export interface ScanResult {
  medications: Array<{
    name: string;
    dosage: string;
    frequency: string;
    durationInDays: number;
    suggestedSchedules: string[];
  }>;
}

