import React, { useState, useEffect, useMemo } from 'react';
import { Pharmacy } from '../types';
import { findNearbyPharmacies } from '../geminiService';

interface PharmacyMapProps {
  pharmacies: Pharmacy[];
}

const ALL_SERVICES = ['24/7', 'Vaccinations', 'Delivery', 'Wheelchair Access'];

const PharmacyMap: React.FC<PharmacyMapProps> = ({ pharmacies: initialPharmacies }) => {
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<any[]>([]);
  const [mapQuery, setMapQuery] = useState('pharmacies in Tunisia');
  const [selectedServices, setSelectedServices] = useState<string[]>([]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
          setUserLocation(loc);
          setMapQuery(`pharmacies near ${loc.lat},${loc.lng}`);
        },
        (err) => console.warn("Geolocation denied", err)
      );
    }
  }, []);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!userLocation) return;

    setIsSearching(true);
    try {
      let q = searchQuery || "pharmacies";
      if (selectedServices.length > 0) {
        q += ` with ${selectedServices.join(', ')}`;
      }
      const result = await findNearbyPharmacies(userLocation.lat, userLocation.lng, q);
      setAiResults(result.grounding);
      setMapQuery(`${q} near ${userLocation.lat},${userLocation.lng}`);
    } catch (error) {
      console.error("Maps search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  const toggleService = (service: string) => {
    setSelectedServices(prev => 
      prev.includes(service) ? prev.filter(s => s !== service) : [...prev, service]
    );
  };

  const filteredPharmacies = useMemo(() => {
    if (selectedServices.length === 0) return initialPharmacies;
    return initialPharmacies.filter(pharmacy => 
      selectedServices.every(service => pharmacy.services.includes(service))
    );
  }, [initialPharmacies, selectedServices]);

  // Icons mapping for services
  const getServiceIcon = (service: string) => {
    switch(service) {
      case '24/7': return 'fa-clock';
      case 'Vaccinations': return 'fa-syringe';
      case 'Delivery': return 'fa-truck';
      case 'Wheelchair Access': return 'fa-wheelchair';
      default: return 'fa-check';
    }
  };

  const embedUrl = `https://www.google.com/maps?q=${encodeURIComponent(mapQuery)}&output=embed`;

  return (
    <div className="h-full space-y-6 animate-in fade-in duration-500">
      <div className="space-y-4">
        <form onSubmit={handleSearch} className="bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-slate-400"></i>
            <input 
              type="text" 
              placeholder="Search for specific pharmacy or medicine availability..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold transition-all"
            />
          </div>
          <button 
            type="submit"
            disabled={isSearching}
            className="px-8 py-4 bg-slate-900 text-white font-black rounded-2xl hover:bg-slate-800 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
          >
            {isSearching ? (
               <i className="fas fa-circle-notch animate-spin"></i>
            ) : (
               <i className="fas fa-location-arrow"></i>
            )}
            SEARCH MAP
          </button>
        </form>

        {/* Service Filters */}
        <div className="flex flex-wrap gap-3 px-2">
          {ALL_SERVICES.map(service => (
            <button
              key={service}
              onClick={() => toggleService(service)}
              className={`px-4 py-2 rounded-full text-xs font-black uppercase tracking-wider transition-all flex items-center gap-2 border ${
                selectedServices.includes(service)
                  ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100'
                  : 'bg-white border-slate-200 text-slate-500 hover:border-blue-400'
              }`}
            >
              <i className={`fas ${getServiceIcon(service)}`}></i>
              {service}
            </button>
          ))}
          {selectedServices.length > 0 && (
            <button 
              onClick={() => setSelectedServices([])}
              className="text-xs font-bold text-slate-400 hover:text-red-500 transition-colors ml-2"
            >
              Clear Filters
            </button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-[calc(100vh-380px)]">
        {/* Results Panel */}
        <div className="lg:col-span-4 space-y-4 overflow-y-auto pr-2 custom-scrollbar">
          {aiResults.length > 0 ? (
            <div className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Verified Map Results</h3>
                <button onClick={() => setAiResults([])} className="text-[10px] font-bold text-blue-600 uppercase">Back to List</button>
              </div>
              {aiResults.map((chunk, idx) => chunk.maps && (
                <a 
                  key={idx}
                  href={chunk.maps.uri}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="block bg-white p-5 rounded-3xl border border-slate-100 hover:border-blue-500 hover:shadow-xl hover:shadow-blue-50 transition-all group"
                >
                  <div className="flex justify-between items-start mb-2">
                    <h3 className="font-black text-slate-900 group-hover:text-blue-600 transition">{chunk.maps.title || "Found Pharmacy"}</h3>
                    <div className="w-8 h-8 bg-blue-50 rounded-lg flex items-center justify-center text-blue-600">
                      <i className="fas fa-external-link-alt text-xs"></i>
                    </div>
                  </div>
                  <p className="text-sm font-medium text-slate-500 line-clamp-2">View details and directions on Google Maps</p>
                </a>
              ))}
            </div>
          ) : (
            <div className="space-y-4">
               <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest px-2">Registered Pharmacies ({filteredPharmacies.length})</h3>
               {filteredPharmacies.length === 0 ? (
                 <div className="p-10 text-center bg-white rounded-3xl border border-dashed border-slate-200">
                   <p className="text-sm font-bold text-slate-400">No pharmacies match these filters.</p>
                 </div>
               ) : (
                 filteredPharmacies.map(pharmacy => (
                  <div 
                    key={pharmacy.id}
                    onClick={() => setMapQuery(`${pharmacy.name}, ${pharmacy.address}`)}
                    className="bg-white p-5 rounded-3xl border border-slate-100 hover:border-emerald-500 hover:shadow-xl hover:shadow-emerald-50 transition-all cursor-pointer group"
                  >
                    <div className="flex justify-between items-start mb-2">
                      <h3 className="font-black text-slate-900 group-hover:text-emerald-600 transition">{pharmacy.name}</h3>
                      <span className={`text-[9px] uppercase font-black px-3 py-1 rounded-full ${
                        pharmacy.stockStatus === 'available' ? 'bg-emerald-100 text-emerald-700' :
                        pharmacy.stockStatus === 'low' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {pharmacy.stockStatus.replace('_', ' ')}
                      </span>
                    </div>
                    <p className="text-sm font-medium text-slate-500 flex items-start gap-3 mb-3">
                      <i className="fas fa-map-pin mt-1 text-slate-300"></i>
                      {pharmacy.address}
                    </p>

                    {/* Services Tags */}
                    <div className="flex flex-wrap gap-1.5 mb-4">
                      {pharmacy.services.map(service => (
                        <span key={service} className="text-[8px] font-black uppercase px-2 py-0.5 bg-slate-50 text-slate-400 rounded-md border border-slate-100">
                          {service}
                        </span>
                      ))}
                    </div>

                    <div className="flex gap-3">
                      <a href={`tel:${pharmacy.phone}`} onClick={e => e.stopPropagation()} className="flex-1 py-3 text-center text-blue-600 bg-blue-50 rounded-xl text-xs font-black hover:bg-blue-100 transition">
                        CALL
                      </a>
                      <button className="flex-1 py-3 text-center text-slate-900 bg-slate-100 rounded-xl text-xs font-black hover:bg-slate-200 transition">
                        SHOW
                      </button>
                    </div>
                  </div>
                ))
               )}
            </div>
          )}
        </div>

        {/* Map Container */}
        <div className="lg:col-span-8 bg-slate-100 rounded-[3rem] relative overflow-hidden shadow-inner border border-slate-200 group">
          <iframe
            title="Pharmacy Map"
            width="100%"
            height="100%"
            frameBorder="0"
            style={{ border: 0 }}
            src={embedUrl}
            allowFullScreen
            className="rounded-[3rem] opacity-90 group-hover:opacity-100 transition-opacity"
          ></iframe>

          {/* Overlay Info */}
          <div className="absolute bottom-8 left-8 right-8 pointer-events-none">
            <div className="bg-slate-900/80 backdrop-blur-md text-white p-6 rounded-[2rem] shadow-2xl flex items-center justify-between border border-white/10">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-500/20">
                  <i className="fas fa-location-dot"></i>
                </div>
                <div>
                  <h4 className="text-sm font-black uppercase tracking-widest text-emerald-400">Map Focus</h4>
                  <p className="font-bold truncate max-w-[200px]">{mapQuery.split('near')[0]}</p>
                </div>
              </div>
              <div className="hidden sm:block text-right">
                <span className="text-[10px] font-black text-slate-400 uppercase block mb-1">Status</span>
                <span className="text-xs font-bold px-3 py-1 bg-white/10 rounded-full">LIVE TRACKING</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PharmacyMap;

import React, { useState } from 'react';
import { User, Medication } from '../types';
import PrescriptionScanner from './PrescriptionScanner';
import MedicationModal from './MedicationModal';

interface DashboardProps {
  user: User;
  medications: Medication[];
  setMedications: React.Dispatch<React.SetStateAction<Medication[]>>;
}

const Dashboard: React.FC<DashboardProps> = ({ medications, setMedications }) => {
  const [showScanner, setShowScanner] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);

  const handleTakeMedication = (id: string) => {
    setMedications(prev => prev.map(m => {
      if (m.id === id) {
        const now = new Date();
        const newHistory = [...m.history, {
          date: now.toISOString().split('T')[0],
          time: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          status: 'taken' as const
        }];

        return { 
          ...m, 
          takenTodayCount: m.takenTodayCount + 1,
          stockCount: Math.max(0, m.stockCount - 1),
          history: newHistory
        };
      }
      return m;
    }));
  };

  const handleAddMedication = (newMed: Partial<Medication>) => {
    const formatted: Medication = {
      id: Math.random().toString(36).substr(2, 9),
      userId: '1',
      name: newMed.name || 'Unknown Medicine',
      dosage: newMed.dosage || '1 unit',
      frequency: newMed.frequency || '1x daily',
      durationInDays: newMed.durationInDays || 7,
      startDate: new Date().toISOString(),
      stockCount: newMed.stockCount || 30,
      threshold: newMed.threshold || 5,
      schedules: newMed.schedules || ['08:00'],
      history: [],
      takenTodayCount: 0
    };
    setMedications(prev => [...prev, formatted]);
    setShowAddModal(false);
  };

  const triggerTestAlert = () => {
    const testMed: Medication = {
      id: 'test-id',
      userId: '1',
      name: 'Test Vitamin',
      dosage: '500mg',
      frequency: 'Test',
      durationInDays: 1,
      startDate: new Date().toISOString(),
      stockCount: 0,
      threshold: 5,
      schedules: [new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false })],
      history: [],
      takenTodayCount: 0
    };
    setMedications(prev => [...prev, testMed]);

    setTimeout(() => {
      setMedications(prev => prev.filter(m => m.id !== 'test-id'));
    }, 5000);
  };

  const totalDosesToday = medications.reduce((acc, m) => acc + m.schedules.length, 0);
  const takenDosesToday = medications.reduce((acc, m) => acc + m.takenTodayCount, 0);
  const progress = totalDosesToday > 0 ? Math.round((takenDosesToday / totalDosesToday) * 100) : 0;

  const lowStockMeds = medications.filter(m => m.stockCount <= m.threshold);

  return (
    <div className="space-y-10 pb-12">
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Progress Card */}
        <div className="lg:col-span-2 bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl text-white relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition duration-500">
            <i className="fas fa-heart-pulse text-8xl"></i>
          </div>
          <div className="relative z-10">
            <h3 className="text-lg font-bold text-slate-400 mb-2">Daily Adherence</h3>
            <div className="flex items-baseline gap-2 mb-6">
              <span className="text-6xl font-black">{progress}%</span>
              <span className="text-slate-500 font-bold uppercase tracking-wider text-sm">Completed</span>
            </div>
            <div className="w-full bg-slate-800 rounded-full h-4 mb-4">
              <div 
                className="bg-blue-500 h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_20px_rgba(59,130,246,0.5)]" 
                style={{ width: `${progress}%` }}
              ></div>
            </div>
            <p className="text-slate-400 font-medium">{takenDosesToday} of {totalDosesToday} doses taken today</p>
          </div>
        </div>

        {/* Action Cards */}
        <div 
          onClick={() => setShowScanner(true)}
          className="bg-emerald-500 p-8 rounded-[2.5rem] shadow-xl shadow-emerald-100 text-white cursor-pointer hover:scale-[1.02] active:scale-95 transition-all flex flex-col justify-between group"
        >
          <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center mb-4 backdrop-blur-md">
            <i className="fas fa-camera text-2xl"></i>
          </div>
          <div>
            <h3 className="text-2xl font-black mb-1">AI Scan</h3>
            <p className="text-emerald-50 text-sm font-medium opacity-80">Extract from prescription</p>
          </div>
        </div>

        <div 
          onClick={triggerTestAlert}
          className="bg-indigo-600 p-8 rounded-[2.5rem] shadow-xl shadow-indigo-100 text-white cursor-pointer hover:scale-[1.02] active:scale-95 transition-all flex flex-col justify-between group"
        >
          <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center mb-4 backdrop-blur-md transition group-hover:bg-white/40">
            <i className="fas fa-vial text-2xl"></i>
          </div>
          <div>
            <h3 className="text-2xl font-black mb-1">Test Alerts</h3>
            <p className="text-indigo-100 text-sm font-medium opacity-80">Simulate immediate notification</p>
          </div>
        </div>
      </div>

      {lowStockMeds.length > 0 && (
        <div className="bg-red-50 border border-red-200 p-6 rounded-[2rem] flex items-center gap-5 animate-pulse shadow-lg shadow-red-100">
          <div className="w-14 h-14 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center shrink-0">
            <i className="fas fa-triangle-exclamation text-2xl"></i>
          </div>
          <div className="flex-1">
            <h4 className="text-lg font-black text-red-900 leading-none mb-1">Stock Rupture Warning</h4>
            <p className="text-sm font-bold text-red-700 opacity-80">
              {lowStockMeds.map(m => m.name).join(', ')} {lowStockMeds.length > 1 ? 'are' : 'is'} running low!
            </p>
          </div>
          <button className="px-6 py-3 bg-red-600 text-white text-xs font-black rounded-xl hover:bg-red-700 transition shadow-md">
            RESTOCK NOW
          </button>
        </div>
      )}

      {/* Medication List */}
      <section>
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-4">
             <h2 className="text-3xl font-black text-slate-900">Current Regimen</h2>
             <button 
               onClick={() => setShowAddModal(true)}
               className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center hover:bg-blue-600 hover:text-white transition-all shadow-sm active:scale-90"
               aria-label="Add Medication"
             >
               <i className="fas fa-plus"></i>
             </button>
          </div>
          <div className="flex gap-2">
             <span className="px-4 py-1.5 bg-white border border-slate-200 rounded-full text-xs font-black text-slate-500 uppercase tracking-widest shadow-sm">
               {medications.length} Medicines
             </span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {medications.length === 0 ? (
            <div className="col-span-full text-center py-24 bg-white rounded-[3rem] border-2 border-dashed border-slate-200">
              <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                 <i className="fas fa-pills text-5xl"></i>
              </div>
              <h3 className="text-2xl font-black text-slate-800 mb-2">No medications found</h3>
              <p className="text-slate-400 max-w-sm mx-auto font-medium">Your medicine cabinet is empty. Start by scanning a prescription or adding your pills manually.</p>
            </div>
          ) : (
            medications.map(med => {
              const stockStatus = med.stockCount === 0 
                ? 'OUT OF STOCK' 
                : med.stockCount <= med.threshold 
                  ? 'LOW STOCK' 
                  : 'IN STOCK';

              const stockColor = med.stockCount === 0 
                ? 'bg-red-500' 
                : med.stockCount <= med.threshold 
                  ? 'bg-amber-500' 
                  : 'bg-emerald-500';

              const stockPercent = Math.min(100, (med.stockCount / (med.threshold * 4)) * 100);

              const allTaken = med.takenTodayCount >= med.schedules.length;

              return (
                <div 
                  key={med.id} 
                  className={`group bg-white p-8 rounded-[2.5rem] shadow-md border-2 transition-all duration-300 flex flex-col gap-8 relative overflow-hidden ${
                    med.stockCount <= med.threshold ? 'border-red-100 shadow-red-50' : 'border-slate-50'
                  } hover:shadow-xl hover:-translate-y-1`}
                >
                  {/* Status Overlay for Empty Stock */}
                  {med.stockCount === 0 && (
                    <div className="absolute inset-0 bg-white/40 backdrop-blur-[2px] z-10 pointer-events-none flex items-center justify-center">
                       <div className="bg-red-600 text-white px-6 py-2 rounded-full font-black text-xs uppercase tracking-widest rotate-[-10deg] shadow-lg border-2 border-white">
                         Needs Refill
                       </div>
                    </div>
                  )}

                  <div className="flex justify-between items-start">
                    <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-lg transition-transform group-hover:scale-110 ${
                      med.stockCount <= med.threshold 
                        ? 'bg-red-50 text-red-600 shadow-red-100' 
                        : 'bg-blue-50 text-blue-600 shadow-blue-100'
                    }`}>
                      <i className={`fas ${med.stockCount === 0 ? 'fa-hourglass-empty' : 'fa-capsules'}`}></i>
                    </div>

                    <div className="text-right">
                      <span className={`text-[10px] px-4 py-1.5 rounded-full font-black uppercase tracking-widest border-2 ${
                        med.stockCount === 0 
                          ? 'bg-red-100 border-red-200 text-red-600' 
                          : med.stockCount <= med.threshold 
                            ? 'bg-amber-100 border-amber-200 text-amber-700' 
                            : 'bg-emerald-50 border-emerald-100 text-emerald-600'
                      }`}>
                        {stockStatus}
                      </span>
                    </div>
                  </div>

                  <div className="space-y-1">
                    <h4 className="text-2xl font-black text-slate-900 leading-tight group-hover:text-blue-600 transition-colors">{med.name}</h4>
                    <div className="flex items-center gap-3">
                      <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">{med.dosage}</p>
                      <span className="w-1 h-1 rounded-full bg-slate-200"></span>
                      <p className="text-xs font-bold text-blue-600 uppercase tracking-widest">{med.frequency}</p>
                    </div>
                  </div>

                  {/* Stock Level Indicator */}
                  <div className="space-y-3">
                    <div className="flex justify-between items-end">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inventory Health</span>
                      <span className="text-sm font-black text-slate-700">{med.stockCount} <span className="text-slate-300 font-bold uppercase text-[9px]">Units Left</span></span>
                    </div>
                    <div className="w-full bg-slate-50 h-2.5 rounded-full overflow-hidden border border-slate-100">
                      <div 
                        className={`h-full rounded-full transition-all duration-700 ${stockColor}`}
                        style={{ width: `${stockPercent}%` }}
                      ></div>
                    </div>
                  </div>

                  {/* Schedule Display */}
                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Today's Progress</span>
                       <span className="text-xs font-black text-slate-800">{med.takenTodayCount}/{med.schedules.length}</span>
                    </div>
                    <div className="flex items-center gap-2 flex-wrap">
                      {med.schedules.map((time, idx) => {
                        const isTaken = idx < med.takenTodayCount;
                        return (
                          <div 
                            key={idx} 
                            className={`px-3 py-2 rounded-xl text-xs font-bold border flex items-center gap-2 transition-all ${
                              isTaken 
                                ? 'bg-emerald-50 border-emerald-100 text-emerald-600 shadow-sm' 
                                : 'bg-slate-50 border-slate-100 text-slate-500'
                            }`}
                          >
                            <i className={`fas ${isTaken ? 'fa-check-circle' : 'fa-clock opacity-40'}`}></i>
                            {time}
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  {/* Main Action Button */}
                  <button 
                    onClick={() => handleTakeMedication(med.id)}
                    disabled={allTaken || med.stockCount === 0}
                    className={`w-full py-5 rounded-[1.5rem] font-black text-sm uppercase tracking-widest transition-all relative z-20 ${
                      med.stockCount === 0 
                        ? 'bg-slate-100 text-slate-300 cursor-not-allowed border border-slate-200'
                        : allTaken
                          ? 'bg-emerald-50 text-emerald-500 cursor-not-allowed border border-emerald-100'
                          : 'bg-slate-900 text-white hover:bg-slate-800 active:scale-95 shadow-xl shadow-slate-200 hover:shadow-blue-200'
                    }`}
                  >
                    <div className="flex items-center justify-center gap-3">
                      {med.stockCount === 0 ? (
                        <>
                          <i className="fas fa-exclamation-circle"></i>
                          Out of Stock
                        </>
                      ) : allTaken ? (
                        <>
                          <i className="fas fa-check-double"></i>
                          Daily Routine Complete
                        </>
                      ) : (
                        <>
                          <i className="fas fa-hand-holding-medical"></i>
                          Mark as Taken
                        </>
                      )}
                    </div>
                  </button>
                </div>
              );
            })
          )}
        </div>
      </section>

      {showScanner && (
        <PrescriptionScanner 
          onClose={() => setShowScanner(false)} 
          onComplete={(newMeds) => {
            newMeds.forEach(m => handleAddMedication(m));
            setShowScanner(false);
          }} 
        />
      )}

      {showAddModal && (
        <MedicationModal 
          onClose={() => setShowAddModal(false)}
          onSave={handleAddMedication}
        />
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { User, UserRole, Medication, Pharmacy } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PharmacyMap from './components/PharmacyMap';
import InventoryManager from './components/InventoryManager';
import HistoryView from './components/HistoryView';
import Auth from './components/Auth';
import NotificationProvider from './components/NotificationProvider';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'dashboard' | 'map' | 'inventory' | 'profile' | 'history'>('dashboard');

  const [medications, setMedications] = useState<Medication[]>([]);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);

  useEffect(() => {
    const mockPharmacies: Pharmacy[] = [
      { 
        id: '1', 
        name: 'Pharmacie de la Marsa', 
        address: 'Av. Habib Bourguiba, La Marsa', 
        location: { lat: 36.878, lng: 10.334 }, 
        phone: '+216 71 000 001', 
        stockStatus: 'available',
        services: ['24/7', 'Vaccinations', 'Delivery']
      },
      { 
        id: '2', 
        name: 'Pharmacie Centrale Tunis', 
        address: 'Rue de Rome, Tunis', 
        location: { lat: 36.806, lng: 10.181 }, 
        phone: '+216 71 000 002', 
        stockStatus: 'low',
        services: ['Vaccinations', 'Wheelchair Access']
      },
      { 
        id: '3', 
        name: 'Pharmacie Ennasr', 
        address: 'Avenue Hédi Nouira, Ariana', 
        location: { lat: 36.858, lng: 10.158 }, 
        phone: '+216 71 000 003', 
        stockStatus: 'out_of_stock',
        services: ['24/7', 'Delivery']
      },
      { 
        id: '4', 
        name: 'Pharmacie Jasmin', 
        address: 'Lac 2, Tunis', 
        location: { lat: 36.832, lng: 10.234 }, 
        phone: '+216 71 000 004', 
        stockStatus: 'available',
        services: ['Delivery', 'Wheelchair Access']
      },
    ];
    setPharmacies(mockPharmacies);

    const savedUser = localStorage.getItem('medcare_user');
    const savedMeds = localStorage.getItem('medcare_meds');

    if (savedUser) setUser(JSON.parse(savedUser));

    if (savedMeds) {
      const parsedMeds: Medication[] = JSON.parse(savedMeds);
      const now = new Date();

      // Auto-deactivation logic based on durationInDays
      const updatedMeds = parsedMeds.map(med => {
        const startDate = new Date(med.startDate);
        const endDate = new Date(startDate);
        endDate.setDate(startDate.getDate() + med.durationInDays);

        // If treatment has expired, we set isActive to false if it isn't already
        if (now > endDate && med.stockCount > 0) {
           // We keep it in history but mark as finished
        }
        return med;
      });

      setMedications(updatedMeds);
    }
  }, []);

  useEffect(() => {
    if (medications.length > 0) {
      localStorage.setItem('medcare_meds', JSON.stringify(medications));
    }
  }, [medications]);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('medcare_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('medcare_user');
    localStorage.removeItem('medcare_meds');
    setMedications([]);
  };

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <NotificationProvider medications={medications}>
      <Layout 
        user={user} 
        currentView={view} 
        onViewChange={setView} 
        onLogout={handleLogout}
      >
        {view === 'dashboard' && <Dashboard user={user} medications={medications} setMedications={setMedications} />}
        {view === 'map' && <PharmacyMap pharmacies={pharmacies} />}
        {view === 'history' && <HistoryView medications={medications} />}
        {view === 'inventory' && user.role === UserRole.PHARMACIST && <InventoryManager />}
        {view === 'profile' && (
          <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-2xl font-bold mb-4">User Profile</h2>
            <div className="space-y-6">
              <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-xl">
                <div className="w-16 h-16 rounded-full bg-blue-600 flex items-center justify-center text-white text-2xl font-bold">
                  {user.name[0]}
                </div>
                <div>
                  <h3 className="text-xl font-bold text-slate-800">{user.name}</h3>
                  <p className="text-slate-500">{user.email}</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 border border-slate-100 rounded-xl">
                  <span className="text-xs text-slate-400 block uppercase font-bold mb-1">Role</span>
                  <span className="font-semibold text-slate-700">{user.role}</span>
                </div>
                <div className="p-4 border border-slate-100 rounded-xl">
                  <span className="text-xs text-slate-400 block uppercase font-bold mb-1">Meds Tracked</span>
                  <span className="font-semibold text-slate-700">{medications.length}</span>
                </div>
              </div>
              <button 
                onClick={handleLogout}
                className="w-full px-4 py-3 bg-red-50 text-red-600 font-bold rounded-xl hover:bg-red-100 transition border border-red-100"
              >
                Sign Out
              </button>
            </div>
          </div>
        )}
      </Layout>
    </NotificationProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { User, Medication } from '../types';
import PrescriptionScanner from './PrescriptionScanner';
import MedicationModal from './MedicationModal';

interface DashboardProps {
  user: User;
  medications: Medication[];
  setMedications: React.Dispatch<React.SetStateAction<Medication[]>>;
}

const Dashboard: React.FC<DashboardProps> = ({ medications, setMedications }) => {
  const [showScanner, setShowScanner] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);

  const handleTakeMedication = (id: string) => {
    setMedications(prev => prev.map(m => {
      if (m.id === id) {
        const now = new Date();
        const newHistory = [...m.history, {
          date: now.toISOString().split('T')[0],
          time: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          status: 'taken' as const
        }];

        return { 
          ...m, 
          takenTodayCount: m.takenTodayCount + 1,
          stockCount: Math.max(0, m.stockCount - 1),
          history: newHistory
        };
      }
      return m;
    }));
  };

  const handleAddMedication = (newMed: Partial<Medication>) => {
    const formatted: Medication = {
      id: Math.random().toString(36).substr(2, 9),
      userId: '1',
      name: newMed.name || 'Unknown Medicine',
      dosage: newMed.dosage || '1 unit',
      frequency: newMed.frequency || '1x daily',
      durationInDays: newMed.durationInDays || 7,
      startDate: new Date().toISOString(),
      stockCount: newMed.stockCount || 30,
      threshold: newMed.threshold || 5,
      schedules: newMed.schedules || ['08:00'],
      history: [],
      takenTodayCount: 0
    };
    setMedications(prev => [...prev, formatted]);
    setShowAddModal(false);
  };

  const triggerTestAlert = () => {
    const testMed: Medication = {
      id: 'test-id',
      userId: '1',
      name: 'Test Vitamin',
      dosage: '500mg',
      frequency: 'Test',
      durationInDays: 1,
      startDate: new Date().toISOString(),
      stockCount: 0,
      threshold: 5,
      schedules: [new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false })],
      history: [],
      takenTodayCount: 0
    };
    setMedications(prev => [...prev, testMed]);

    setTimeout(() => {
      setMedications(prev => prev.filter(m => m.id !== 'test-id'));
    }, 5000);
  };

  const isExpired = (med: Medication) => {
    const start = new Date(med.startDate);
    const end = new Date(start);
    end.setDate(start.getDate() + med.durationInDays);
    return new Date() > end;
  };

  const activeMeds = medications.filter(m => !isExpired(m));
  const completedMeds = medications.filter(m => isExpired(m));

  const totalDosesToday = activeMeds.reduce((acc, m) => acc + m.schedules.length, 0);
  const takenDosesToday = activeMeds.reduce((acc, m) => acc + m.takenTodayCount, 0);
  const progress = totalDosesToday > 0 ? Math.round((takenDosesToday / totalDosesToday) * 100) : 0;

  const lowStockMeds = activeMeds.filter(m => m.stockCount <= m.threshold);

  return (
    <div className="space-y-10 pb-12">
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Progress Card */}
        <div className="lg:col-span-2 bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl text-white relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition duration-500">
            <i className="fas fa-heart-pulse text-8xl"></i>
          </div>
          <div className="relative z-10">
            <h3 className="text-lg font-bold text-slate-400 mb-2">Daily Adherence</h3>
            <div className="flex items-baseline gap-2 mb-6">
              <span className="text-6xl font-black">{progress}%</span>
              <span className="text-slate-500 font-bold uppercase tracking-wider text-sm">Completed</span>
            </div>
            <div className="w-full bg-slate-800 rounded-full h-4 mb-4">
              <div 
                className="bg-blue-500 h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_20px_rgba(59,130,246,0.5)]" 
                style={{ width: `${progress}%` }}
              ></div>
            </div>
            <p className="text-slate-400 font-medium">{takenDosesToday} of {totalDosesToday} doses taken today</p>
          </div>
        </div>

        {/* Action Cards */}
        <div 
          onClick={() => setShowScanner(true)}
          className="bg-emerald-500 p-8 rounded-[2.5rem] shadow-xl shadow-emerald-100 text-white cursor-pointer hover:scale-[1.02] active:scale-95 transition-all flex flex-col justify-between group"
        >
          <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center mb-4 backdrop-blur-md">
            <i className="fas fa-camera text-2xl"></i>
          </div>
          <div>
            <h3 className="text-2xl font-black mb-1">AI Scan</h3>
            <p className="text-emerald-50 text-sm font-medium opacity-80">Extract from prescription</p>
          </div>
        </div>

        <div 
          onClick={triggerTestAlert}
          className="bg-indigo-600 p-8 rounded-[2.5rem] shadow-xl shadow-indigo-100 text-white cursor-pointer hover:scale-[1.02] active:scale-95 transition-all flex flex-col justify-between group"
        >
          <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center mb-4 backdrop-blur-md transition group-hover:bg-white/40">
            <i className="fas fa-vial text-2xl"></i>
          </div>
          <div>
            <h3 className="text-2xl font-black mb-1">Test Alerts</h3>
            <p className="text-indigo-100 text-sm font-medium opacity-80">Simulate immediate notification</p>
          </div>
        </div>
      </div>

      {lowStockMeds.length > 0 && (
        <div className="bg-red-50 border border-red-200 p-6 rounded-[2rem] flex items-center gap-5 animate-pulse shadow-lg shadow-red-100">
          <div className="w-14 h-14 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center shrink-0">
            <i className="fas fa-triangle-exclamation text-2xl"></i>
          </div>
          <div className="flex-1">
            <h4 className="text-lg font-black text-red-900 leading-none mb-1">Stock Rupture Warning</h4>
            <p className="text-sm font-bold text-red-700 opacity-80">
              {lowStockMeds.map(m => m.name).join(', ')} {lowStockMeds.length > 1 ? 'are' : 'is'} running low!
            </p>
          </div>
          <button className="px-6 py-3 bg-red-600 text-white text-xs font-black rounded-xl hover:bg-red-700 transition shadow-md">
            RESTOCK NOW
          </button>
        </div>
      )}

      {/* Active Medication List */}
      <section>
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-4">
             <h2 className="text-3xl font-black text-slate-900">Current Regimen</h2>
             <button 
               onClick={() => setShowAddModal(true)}
               className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center hover:bg-blue-600 hover:text-white transition-all shadow-sm active:scale-90"
               aria-label="Add Medication"
             >
               <i className="fas fa-plus"></i>
             </button>
          </div>
          <div className="flex gap-2">
             <span className="px-4 py-1.5 bg-white border border-slate-200 rounded-full text-xs font-black text-slate-500 uppercase tracking-widest shadow-sm">
               {activeMeds.length} Active
             </span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {activeMeds.length === 0 ? (
            <div className="col-span-full text-center py-24 bg-white rounded-[3rem] border-2 border-dashed border-slate-200">
              <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                 <i className="fas fa-pills text-5xl"></i>
              </div>
              <h3 className="text-2xl font-black text-slate-800 mb-2">No active medications</h3>
              <p className="text-slate-400 max-w-sm mx-auto font-medium">Your current treatment plan is empty. Scan a prescription to start tracking.</p>
            </div>
          ) : (
            activeMeds.map(med => <MedicationCard key={med.id} med={med} onTake={handleTakeMedication} />)
          )}
        </div>
      </section>

      {/* Completed Treatments */}
      {completedMeds.length > 0 && (
        <section className="mt-16">
          <div className="flex items-center gap-4 mb-8">
            <h2 className="text-xl font-black text-slate-400 uppercase tracking-widest">Finished Regimens</h2>
            <div className="h-px flex-1 bg-slate-100"></div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 opacity-60 grayscale hover:grayscale-0 transition-all duration-500">
            {completedMeds.map(med => <MedicationCard key={med.id} med={med} onTake={() => {}} isCompleted />)}
          </div>
        </section>
      )}

      {showScanner && (
        <PrescriptionScanner 
          onClose={() => setShowScanner(false)} 
          onComplete={(newMeds) => {
            newMeds.forEach(m => handleAddMedication(m));
            setShowScanner(false);
          }} 
        />
      )}

      {showAddModal && (
        <MedicationModal 
          onClose={() => setShowAddModal(false)}
          onSave={handleAddMedication}
        />
      )}
    </div>
  );
};

const MedicationCard: React.FC<{ med: Medication, onTake: (id: string) => void, isCompleted?: boolean }> = ({ med, onTake, isCompleted }) => {
  const stockStatus = med.stockCount === 0 
    ? 'OUT OF STOCK' 
    : med.stockCount <= med.threshold 
      ? 'LOW STOCK' 
      : 'IN STOCK';

  const stockColor = med.stockCount === 0 
    ? 'bg-red-500' 
    : med.stockCount <= med.threshold 
      ? 'bg-amber-500' 
      : 'bg-emerald-500';

  const stockPercent = Math.min(100, (med.stockCount / (med.threshold * 4)) * 100);
  const allTaken = med.takenTodayCount >= med.schedules.length;

  return (
    <div 
      className={`group bg-white p-8 rounded-[2.5rem] shadow-md border-2 transition-all duration-300 flex flex-col gap-8 relative overflow-hidden ${
        isCompleted ? 'border-slate-100 bg-slate-50/30' : 
        med.stockCount <= med.threshold ? 'border-red-100 shadow-red-50' : 'border-slate-50'
      } hover:shadow-xl hover:-translate-y-1`}
    >
      {/* Status Overlay for Completed or Empty */}
      {(med.stockCount === 0 || isCompleted) && (
        <div className="absolute inset-0 bg-white/40 backdrop-blur-[2px] z-10 pointer-events-none flex items-center justify-center">
           <div className={`${isCompleted ? 'bg-slate-900' : 'bg-red-600'} text-white px-6 py-2 rounded-full font-black text-xs uppercase tracking-widest rotate-[-10deg] shadow-lg border-2 border-white`}>
             {isCompleted ? 'Treatment Finished' : 'Needs Refill'}
           </div>
        </div>
      )}

      <div className="flex justify-between items-start">
        <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-3xl shadow-lg transition-transform group-hover:scale-110 ${
          isCompleted ? 'bg-slate-100 text-slate-400' :
          med.stockCount <= med.threshold 
            ? 'bg-red-50 text-red-600 shadow-red-100' 
            : 'bg-blue-50 text-blue-600 shadow-blue-100'
        }`}>
          <i className={`fas ${isCompleted ? 'fa-check-double' : med.stockCount === 0 ? 'fa-hourglass-empty' : 'fa-capsules'}`}></i>
        </div>

        {!isCompleted && (
          <div className="text-right">
            <span className={`text-[10px] px-4 py-1.5 rounded-full font-black uppercase tracking-widest border-2 ${
              med.stockCount === 0 
                ? 'bg-red-100 border-red-200 text-red-600' 
                : med.stockCount <= med.threshold 
                  ? 'bg-amber-100 border-amber-200 text-amber-700' 
                  : 'bg-emerald-50 border-emerald-100 text-emerald-600'
            }`}>
              {stockStatus}
            </span>
          </div>
        )}
      </div>

      <div className="space-y-1">
        <h4 className={`text-2xl font-black leading-tight transition-colors ${isCompleted ? 'text-slate-400' : 'text-slate-900 group-hover:text-blue-600'}`}>{med.name}</h4>
        <div className="flex items-center gap-3">
          <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">{med.dosage}</p>
          <span className="w-1 h-1 rounded-full bg-slate-200"></span>
          <p className={`text-xs font-bold uppercase tracking-widest ${isCompleted ? 'text-slate-300' : 'text-blue-600'}`}>{med.frequency}</p>
        </div>
      </div>

      {!isCompleted && (
        <>
          <div className="space-y-3">
            <div className="flex justify-between items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inventory Health</span>
              <span className="text-sm font-black text-slate-700">{med.stockCount} <span className="text-slate-300 font-bold uppercase text-[9px]">Units Left</span></span>
            </div>
            <div className="w-full bg-slate-50 h-2.5 rounded-full overflow-hidden border border-slate-100">
              <div 
                className={`h-full rounded-full transition-all duration-700 ${stockColor}`}
                style={{ width: `${stockPercent}%` }}
              ></div>
            </div>
          </div>

          <div className="space-y-3">
            <div className="flex justify-between items-center">
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Today's Progress</span>
               <span className="text-xs font-black text-slate-800">{med.takenTodayCount}/{med.schedules.length}</span>
            </div>
            <div className="flex items-center gap-2 flex-wrap">
              {med.schedules.map((time, idx) => {
                const isTaken = idx < med.takenTodayCount;
                return (
                  <div 
                    key={idx} 
                    className={`px-3 py-2 rounded-xl text-xs font-bold border flex items-center gap-2 transition-all ${
                      isTaken 
                        ? 'bg-emerald-50 border-emerald-100 text-emerald-600 shadow-sm' 
                        : 'bg-slate-50 border-slate-100 text-slate-500'
                    }`}
                  >
                    <i className={`fas ${isTaken ? 'fa-check-circle' : 'fa-clock opacity-40'}`}></i>
                    {time}
                  </div>
                );
              })}
            </div>
          </div>

          <button 
            onClick={() => onTake(med.id)}
            disabled={allTaken || med.stockCount === 0}
            className={`w-full py-5 rounded-[1.5rem] font-black text-sm uppercase tracking-widest transition-all relative z-20 ${
              med.stockCount === 0 
                ? 'bg-slate-100 text-slate-300 cursor-not-allowed border border-slate-200'
                : allTaken
                  ? 'bg-emerald-50 text-emerald-500 cursor-not-allowed border border-emerald-100'
                  : 'bg-slate-900 text-white hover:bg-slate-800 active:scale-95 shadow-xl shadow-slate-200 hover:shadow-blue-200'
            }`}
          >
            <div className="flex items-center justify-center gap-3">
              {med.stockCount === 0 ? (
                <>
                  <i className="fas fa-exclamation-circle"></i>
                  Out of Stock
                </>
              ) : allTaken ? (
                <>
                  <i className="fas fa-check-double"></i>
                  Daily Routine Complete
                </>
              ) : (
                <>
                  <i className="fas fa-hand-holding-medical"></i>
                  Mark as Taken
                </>
              )}
            </div>
          </button>
        </>
      )}

      {isCompleted && (
        <div className="mt-auto pt-6 border-t border-slate-100">
           <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest text-center">Treatment course ended</p>
        </div>
      )}
    </div>
  );
};

