import React, { useState, useMemo } from 'react';

interface InventoryItem {
  id: number;
  name: string;
  stock: number;
  category: string;
  status: string;
  expiryDate: string; // ISO format string
  durationInDays?: number;
  startDate?: string;
}

type SortConfig = {
  key: keyof InventoryItem;
  direction: 'asc' | 'desc';
} | null;

const InventoryManager: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([
    { id: 1, name: 'Paracetamol 500mg', stock: 450, category: 'Pain Relief', status: 'In Stock', expiryDate: '2026-05-20' },
    { id: 2, name: 'Amoxicillin 1g', stock: 12, category: 'Antibiotics', status: 'Low Stock', expiryDate: '2024-08-15' },
    { id: 3, name: 'Metformin 850mg', stock: 0, category: 'Diabetes', status: 'Out of Stock', expiryDate: '2025-12-01' },
    { id: 4, name: 'Vitamin C 1000mg', stock: 230, category: 'Supplements', status: 'In Stock', expiryDate: '2025-01-10' },
    { id: 5, name: 'Insulin Glargine', stock: 45, category: 'Diabetes', status: 'In Stock', expiryDate: '2024-04-30' },
    // Example of a finished patient medication treatment
    { id: 6, name: 'Augmentin 1g', stock: 2, category: 'Antibiotics', status: 'In Stock', expiryDate: '2024-12-30', durationInDays: 7, startDate: '2023-11-01' },
  ]);

  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'expiryDate', direction: 'asc' });

  const requestSort = (key: keyof InventoryItem) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const sortedItems = useMemo(() => {
    const sortableItems = [...items];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];

        if (valA === undefined || valB === undefined) return 0;

        if (valA < valB) {
          return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (valA > valB) {
          return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
      });
    }
    return sortableItems;
  }, [items, sortConfig]);

  const isExpiringSoon = (dateStr: string) => {
    const expiry = new Date(dateStr);
    const today = new Date();
    const diffTime = expiry.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays > 0 && diffDays <= 90; // Expiring within 3 months
  };

  const isExpired = (dateStr: string) => {
    return new Date(dateStr) < new Date();
  };

  const isTreatmentFinished = (item: InventoryItem) => {
    if (!item.startDate || !item.durationInDays) return false;
    const start = new Date(item.startDate);
    const end = new Date(start);
    end.setDate(start.getDate() + item.durationInDays);
    return new Date() > end;
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900">Inventory Management</h2>
          <p className="text-slate-500 font-medium">Monitor stock levels and medication shelf life</p>
        </div>
        <button className="px-6 py-3 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-200 transition flex items-center gap-3 active:scale-95">
          <i className="fas fa-plus"></i> ADD MEDICINE
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left min-w-[800px]">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th 
                  onClick={() => requestSort('name')}
                  className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-blue-600 transition"
                >
                  Medicine Name {sortConfig?.key === 'name' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest">Category</th>
                <th 
                  onClick={() => requestSort('stock')}
                  className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-blue-600 transition text-center"
                >
                  Stock Level {sortConfig?.key === 'stock' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th 
                  onClick={() => requestSort('expiryDate')}
                  className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-blue-600 transition text-center bg-blue-50/30"
                >
                  Expiry Date {sortConfig?.key === 'expiryDate' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {sortedItems.map((item) => {
                const treatmentFinished = isTreatmentFinished(item);
                const expired = isExpired(item.expiryDate);

                return (
                  <tr key={item.id} className={`hover:bg-slate-50/50 transition group ${treatmentFinished ? 'opacity-50 grayscale' : ''}`}>
                    <td className="px-8 py-6">
                      <div className="font-black text-slate-900">{item.name}</div>
                      {treatmentFinished && (
                        <div className="text-[9px] font-black text-slate-400 uppercase tracking-wider">Treatment Course Ended</div>
                      )}
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-sm font-bold text-slate-400 uppercase tracking-wider">{item.category}</span>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`font-black ${item.stock <= 20 ? 'text-red-500' : 'text-slate-700'}`}>
                        {item.stock}
                      </span>
                      <span className="text-[10px] ml-1 text-slate-400 font-bold uppercase">UNITS</span>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <div className="flex flex-col items-center">
                        <span className={`font-black text-sm ${
                          expired ? 'text-red-600' : 
                          isExpiringSoon(item.expiryDate) ? 'text-amber-600' : 'text-slate-800'
                        }`}>
                          {new Date(item.expiryDate).toLocaleDateString('fr-FR', { month: 'short', year: 'numeric', day: 'numeric' })}
                        </span>
                        {expired && (
                          <span className="text-[9px] font-black text-red-500 uppercase mt-0.5 animate-pulse">EXPIRED</span>
                        )}
                        {isExpiringSoon(item.expiryDate) && !expired && (
                          <span className="text-[9px] font-black text-amber-500 uppercase mt-0.5">EXPIRING SOON</span>
                        )}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                        treatmentFinished ? 'bg-slate-900 text-white' :
                        item.status === 'In Stock' ? 'bg-emerald-100 text-emerald-700' :
                        item.status === 'Low Stock' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {treatmentFinished ? 'Finished' : item.status}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <div className="flex items-center justify-end gap-3">
                        <button className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 hover:bg-blue-600 hover:text-white transition shadow-sm">
                          <i className="fas fa-edit"></i>
                        </button>
                        <button className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 hover:bg-red-600 hover:text-white transition shadow-sm">
                          <i className="fas fa-trash"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {sortedItems.length === 0 && (
          <div className="p-20 text-center">
            <i className="fas fa-box-open text-6xl text-slate-200 mb-6"></i>
            <p className="text-xl font-bold text-slate-400">Inventory is empty.</p>
          </div>
        )}
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
           <div className="w-14 h-14 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center text-xl">
             <i className="fas fa-calendar-times"></i>
           </div>
           <div>
             <h4 className="text-2xl font-black text-slate-900">{items.filter(i => isExpired(i.expiryDate)).length}</h4>
             <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Expired Products</p>
           </div>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
           <div className="w-14 h-14 bg-amber-50 text-amber-600 rounded-2xl flex items-center justify-center text-xl">
             <i className="fas fa-hourglass-half"></i>
           </div>
           <div>
             <h4 className="text-2xl font-black text-slate-900">{items.filter(i => isExpiringSoon(i.expiryDate) && !isExpired(i.expiryDate)).length}</h4>
             <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Expiring Soon</p>
           </div>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
