           <div>
             <h4 className="text-2xl font-black text-slate-900">{items.filter(i => isTreatmentFinished(i)).length}</h4>
             <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Finished Regimens</p>
           </div>
        </div>
      </div>
    </div>
  );
};

