import React, { useState, useMemo } from 'react';

interface InventoryItem {
  id: number;
  name: string;
  stock: number;
  category: string;
  expiryDate: string; // ISO format string
  durationInDays?: number;
  startDate?: string;
  threshold: number;
}

type SortConfig = {
  key: keyof InventoryItem;
  direction: 'asc' | 'desc';
} | null;

const InventoryManager: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([
    { id: 1, name: 'Paracetamol 500mg', stock: 450, category: 'Pain Relief', expiryDate: '2026-05-20', threshold: 50 },
    { id: 2, name: 'Amoxicillin 1g', stock: 12, category: 'Antibiotics', expiryDate: '2024-08-15', threshold: 20 },
    { id: 3, name: 'Metformin 850mg', stock: 0, category: 'Diabetes', expiryDate: '2025-12-01', threshold: 15 },
    { id: 4, name: 'Vitamin C 1000mg', stock: 230, category: 'Supplements', expiryDate: '2025-01-10', threshold: 30 },
    { id: 5, name: 'Insulin Glargine', stock: 45, category: 'Diabetes', expiryDate: '2024-04-30', threshold: 10 },
    { id: 6, name: 'Augmentin 1g', stock: 2, category: 'Antibiotics', expiryDate: '2024-12-30', durationInDays: 7, startDate: '2023-11-01', threshold: 5 },
  ]);

  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'expiryDate', direction: 'asc' });

  const handleStockChange = (id: number, newStock: number) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, stock: Math.max(0, newStock) } : item
    ));
  };

  const requestSort = (key: keyof InventoryItem) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const isExpiringSoon = (dateStr: string) => {
    const expiry = new Date(dateStr);
    const today = new Date();
    const diffTime = expiry.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays > 0 && diffDays <= 90;
  };

  const isExpired = (dateStr: string) => {
    return new Date(dateStr) < new Date();
  };

  const isTreatmentFinished = (item: InventoryItem) => {
    if (!item.startDate || !item.durationInDays) return false;
    const start = new Date(item.startDate);
    const end = new Date(start);
    end.setDate(start.getDate() + item.durationInDays);
    return new Date() > end;
  };

  const getStatus = (item: InventoryItem) => {
    if (isTreatmentFinished(item)) return { label: 'Finished', color: 'bg-slate-900 text-white' };
    if (item.stock === 0) return { label: 'Out of Stock', color: 'bg-red-100 text-red-700' };
    if (item.stock <= item.threshold) return { label: 'Low Stock', color: 'bg-amber-100 text-amber-700' };
    return { label: 'In Stock', color: 'bg-emerald-100 text-emerald-700' };
  };

  const sortedItems = useMemo(() => {
    const sortableItems = [...items];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];
        if (valA === undefined || valB === undefined) return 0;
        if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [items, sortConfig]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Inventory Hub</h2>
          <p className="text-slate-500 font-medium">Real-time stock management and expiry tracking</p>
        </div>
        <button className="px-6 py-3 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-200 transition flex items-center gap-3 active:scale-95">
          <i className="fas fa-plus"></i> ADD MEDICINE
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left min-w-[800px]">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th 
                  onClick={() => requestSort('name')}
                  className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-blue-600 transition"
                >
                  Medicine {sortConfig?.key === 'name' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest">Category</th>
                <th 
                  onClick={() => requestSort('stock')}
                  className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-blue-600 transition text-center"
                >
                  Stock Level {sortConfig?.key === 'stock' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th 
                  onClick={() => requestSort('expiryDate')}
                  className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-blue-600 transition text-center bg-blue-50/30"
                >
                  Shelf Life {sortConfig?.key === 'expiryDate' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                </th>
                <th className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest">Calculated Status</th>
                <th className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {sortedItems.map((item) => {
                const treatmentFinished = isTreatmentFinished(item);
                const expired = isExpired(item.expiryDate);
                const status = getStatus(item);

                return (
                  <tr key={item.id} className={`hover:bg-slate-50/50 transition group ${treatmentFinished ? 'opacity-60' : ''}`}>
                    <td className="px-8 py-6">
                      <div className="font-black text-slate-900 group-hover:text-blue-600 transition-colors">{item.name}</div>
                      {treatmentFinished && (
                        <div className="text-[9px] font-black text-slate-400 uppercase tracking-wider mt-1 flex items-center gap-1">
                          <i className="fas fa-flag-checkered"></i> Regimen Completed
                        </div>
                      )}
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-100 px-3 py-1 rounded-lg">
                        {item.category}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <div className="flex items-center justify-center gap-2">
                        <div className="relative group/input">
                          <input 
                            type="number" 
                            min="0"
                            value={item.stock}
                            onChange={(e) => handleStockChange(item.id, parseInt(e.target.value) || 0)}
                            className={`w-20 px-3 py-2 text-center font-black rounded-xl border-2 transition-all outline-none ${
                              item.stock === 0 ? 'border-red-200 bg-red-50 text-red-600' :
                              item.stock <= item.threshold ? 'border-amber-200 bg-amber-50 text-amber-700' :
                              'border-slate-100 bg-slate-50 text-slate-700 focus:border-blue-500 focus:bg-white'
                            }`}
                          />
                        </div>
                        <span className="text-[9px] text-slate-400 font-black uppercase">Units</span>
                      </div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <div className="flex flex-col items-center">
                        <span className={`font-black text-sm ${
                          expired ? 'text-red-600' : 
                          isExpiringSoon(item.expiryDate) ? 'text-amber-600' : 'text-slate-800'
                        }`}>
                          {new Date(item.expiryDate).toLocaleDateString('fr-FR', { month: 'short', year: 'numeric', day: 'numeric' })}
                        </span>
                        {expired ? (
                          <span className="text-[9px] font-black text-red-500 uppercase mt-0.5 px-2 py-0.5 bg-red-50 rounded-md animate-pulse">EXPIRED</span>
