                        {status.label}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <button className="w-10 h-10 bg-slate-50 text-slate-400 rounded-xl flex items-center justify-center hover:bg-blue-600 hover:text-white transition-all transform active:scale-90">
                          <i className="fas fa-edit"></i>
                        </button>
                        <button className="w-10 h-10 bg-slate-50 text-slate-400 rounded-xl flex items-center justify-center hover:bg-red-600 hover:text-white transition-all transform active:scale-90">
                          <i className="fas fa-trash"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <SummaryCard 
          icon="fa-calendar-times" 
          value={items.filter(i => isExpired(i.expiryDate)).length} 
          label="Expired Products" 
          color="text-red-600" 
          bg="bg-red-50" 
        />
        <SummaryCard 
          icon="fa-hourglass-half" 
          value={items.filter(i => isExpiringSoon(i.expiryDate) && !isExpired(i.expiryDate)).length} 
          label="Expiring Soon" 
          color="text-amber-600" 
          bg="bg-amber-50" 
        />
        <SummaryCard 
          icon="fa-boxes-stacked" 
          value={items.filter(i => i.stock <= i.threshold && i.stock > 0).length} 
          label="Low Stock Alert" 
          color="text-orange-600" 
          bg="bg-orange-50" 
        />
        <SummaryCard 
          icon="fa-flag-checkered" 
          value={items.filter(i => isTreatmentFinished(i)).length} 
          label="Finished Regimens" 
          color="text-slate-900" 
          bg="bg-slate-100" 
        />
      </div>
    </div>
