  const getEmbedUrl = () => {
    const baseUrl = "https://www.google.com/maps";
    if (viewMode === 'directions' && activePharmacy) {
      const destination = activePharmacy.address ? `${activePharmacy.name}, ${activePharmacy.address}` : `${activePharmacy.name}`;
      return `${baseUrl}?saddr=My+Location&daddr=${encodeURIComponent(destination)}&output=embed`;
    }
    return `${baseUrl}?q=${encodeURIComponent(mapQuery)}&output=embed`;
  };

  return (
