          </button>
        </form>

        {/* Filters */}
        <div className="flex flex-wrap items-center gap-3 px-2">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mr-2">Filter Services:</span>
          {ALL_SERVICES.map(service => (
