      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-[calc(100vh-400px)]">
        {/* Results Sidebar */}
        <div className="lg:col-span-4 space-y-4 overflow-y-auto pr-2 custom-scrollbar">
          {/* AI Grounding Results Section */}
          {aiResults.length > 0 && (
