import mongoose, { Schema } from 'mongoose';

// USER SCHEMA
const UserSchema = new Schema({
  name: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  password: { type: String, required: true },
  role: { type: String, enum: ['PATIENT', 'PHARMACIST', 'ADMIN'], default: 'PATIENT' },
  location: {
    lat: Number,
    lng: Number
  }
}, { timestamps: true });

// MEDICATION SCHEMA
const MedicationSchema = new Schema({
  userId: { type: Schema.Types.ObjectId, ref: 'User', required: true },
  name: { type: String, required: true },
  dosage: String,
  frequency: String,
  durationInDays: { type: Number, default: 7 },
  startDate: { type: Date, default: Date.now },
  stockCount: { type: Number, default: 30 },
  threshold: { type: Number, default: 5 },
  schedules: [{ type: String }],
  isActive: { type: Boolean, default: true },
  history: [{
    date: String,
    time: String,
    status: { type: String, enum: ['taken', 'missed'] }
  }]
}, { timestamps: true });

export const UserModel = mongoose.model('User', UserSchema);
export const MedicationModel = mongoose.model('Medication', MedicationSchema);

import express from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import { UserModel, MedicationModel } from './models';

const app = express();
const JWT_SECRET = process.env.JWT_SECRET || 'medcare_secret_key_2024';

app.use(express.json() as any);
app.use(cors() as any);

// --- AUTH MIDDLEWARE ---
const authenticate = (req: any, res: any, next: any) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (e) {
    res.status(401).json({ error: 'Invalid token' });
  }
};

// --- AUTH ENDPOINTS ---
app.post('/api/auth/register', async (req, res) => {
  try {
    const { name, email, password, role } = req.body;
    const hashedPassword = await bcrypt.hash(password, 10);
    const user = await UserModel.create({ name, email, password: hashedPassword, role });
    const token = jwt.sign({ id: user._id, role: user.role }, JWT_SECRET);
    res.json({ token, user: { id: user._id, name: user.name, email: user.email, role: user.role } });
  } catch (err) {
    res.status(400).json({ error: 'Registration failed' });
  }
});

app.post('/api/auth/login', async (req, res) => {
  try {
    const { email, password } = req.body;
    const user = await UserModel.findOne({ email });
    if (!user || !(await bcrypt.compare(password, user.password))) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }
    const token = jwt.sign({ id: user._id, role: user.role }, JWT_SECRET);
    res.json({ token, user: { id: user._id, name: user.name, email: user.email, role: user.role } });
  } catch (err) {
    res.status(500).json({ error: 'Login error' });
  }
});

// --- MEDICATION ENDPOINTS ---
app.get('/api/medications', authenticate, async (req: any, res) => {
  try {
    const meds = await MedicationModel.find({ userId: req.user.id });
    res.json(meds);
  } catch (err) {
    res.status(500).json({ error: 'Failed to fetch medications' });
  }
});

app.post('/api/medications', authenticate, async (req: any, res) => {
  try {
    const med = await MedicationModel.create({ ...req.body, userId: req.user.id });
    res.json(med);
  } catch (err) {
    res.status(400).json({ error: 'Failed to create medication' });
  }
});

app.patch('/api/medications/:id/take', authenticate, async (req: any, res) => {
  try {
    const med = await MedicationModel.findOne({ _id: req.params.id, userId: req.user.id });
    if (!med) return res.status(404).send('Not found');

    const now = new Date();
    med.stockCount = Math.max(0, med.stockCount - 1);
    med.history.push({
      date: now.toISOString().split('T')[0],
      time: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      status: 'taken'
    });

    await med.save();
    res.json(med);
  } catch (err) {
    res.status(500).json({ error: 'Update failed' });
  }
});

app.delete('/api/medications/:id', authenticate, async (req: any, res) => {
  try {
    await MedicationModel.deleteOne({ _id: req.params.id, userId: req.user.id });
    res.sendStatus(204);
  } catch (err) {
    res.status(500).json({ error: 'Deletion failed' });
  }
});

const PORT = process.env.PORT || 5000;
mongoose.connect(process.env.MONGODB_URI || 'mongodb://localhost:27017/medcare')
  .then(() => app.listen(PORT, () => console.log(`Server running on port ${PORT}`)))
  .catch(err => console.error(err));

