import React, { useState, useEffect } from 'react';
import { User, Medication, UserRole } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PharmacyMap from './components/PharmacyMap';
import HistoryView from './components/HistoryView';
import Auth from './components/Auth';
import NotificationProvider from './components/NotificationProvider';
import InventoryManager from './components/InventoryManager';

const API_BASE = 'http://localhost:5000/api';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(localStorage.getItem('token'));
  const [view, setView] = useState<'dashboard' | 'map' | 'profile' | 'history' | 'inventory'>('dashboard');
  const [medications, setMedications] = useState<Medication[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    if (savedUser && token) {
      setUser(JSON.parse(savedUser));
      fetchMedications(token);
    }
  }, [token]);

  const fetchMedications = async (userToken: string) => {
    try {
      // Attempt real fetch
      const res = await fetch(`${API_BASE}/medications`, {
        headers: { 'Authorization': `Bearer ${userToken}` }
      });
      if (!res.ok) throw new Error();
      const data = await res.json();
      setMedications(data);
    } catch (err) {
      // Fallback to localStorage for preview mode
      const localMeds = localStorage.getItem('medcare_meds');
      if (localMeds) {
        setMedications(JSON.parse(localMeds));
      }
    }
  };

  const handleLogin = (u: User, t: string) => {
    setUser(u);
    setToken(t);
    localStorage.setItem('user', JSON.stringify(u));
    localStorage.setItem('token', t);
    fetchMedications(t);
  };

  const handleLogout = () => {
    setUser(null);
    setToken(null);
    localStorage.clear();
  };

  const handleMedicationChange = (newMeds: Medication[] | ((prev: Medication[]) => Medication[])) => {
    setMedications(prev => {
      const updated = typeof newMeds === 'function' ? newMeds(prev) : newMeds;
      localStorage.setItem('medcare_meds', JSON.stringify(updated));
      return updated;
    });
  };

  if (!user || !token) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <NotificationProvider medications={medications}>
      <Layout 
        user={user} 
        currentView={view} 
        onViewChange={setView} 
        onLogout={handleLogout}
      >
        {view === 'dashboard' && (
          <Dashboard 
            user={user} 
            medications={medications} 
            setMedications={handleMedicationChange as any} 
          />
        )}
        {view === 'map' && <PharmacyMap pharmacies={[]} />}
        {view === 'history' && <HistoryView medications={medications} />}
        {view === 'inventory' && <InventoryManager />}
        {view === 'profile' && (
           <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-100 max-w-2xl">
             <div className="flex items-center gap-6 mb-8">
                <div className="w-20 h-20 rounded-3xl bg-blue-600 flex items-center justify-center text-white text-3xl font-black shadow-xl shadow-blue-100">
                  {user.name[0]}
                </div>
                <div>
                  <h2 className="text-3xl font-black text-slate-900">{user.name}</h2>
                  <p className="text-slate-500 font-medium">{user.email}</p>
                </div>
             </div>
             <div className="grid grid-cols-2 gap-4 mb-8">
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Account Role</span>
                  <span className="font-bold text-blue-600">{user.role}</span>
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Active Treatments</span>
                  <span className="font-bold text-slate-700">{medications.length}</span>
                </div>
             </div>
             <button 
               onClick={handleLogout}
               className="px-8 py-4 bg-red-50 text-red-600 font-black rounded-2xl hover:bg-red-100 transition flex items-center gap-3"
             >
               <i className="fas fa-sign-out-alt"></i> SIGN OUT
             </button>
           </div>
        )}
      </Layout>
    </NotificationProvider>
  );
};

