import React, { useState, useEffect, useMemo } from 'react';
import { Pharmacy } from '../types';
import { findNearbyPharmacies } from '../geminiService';

interface PharmacyMapProps {
  pharmacies: Pharmacy[];
}

interface RouteStep {
  instruction: string;
  distance: string;
}

const ALL_SERVICES = ['24/7', 'Vaccinations', 'Delivery', 'Wheelchair Access'];

const PharmacyMap: React.FC<PharmacyMapProps> = ({ pharmacies: initialPharmacies }) => {
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [aiResults, setAiResults] = useState<any[]>([]);
  const [mapQuery, setMapQuery] = useState('pharmacies in Tunisia');
  const [selectedServices, setSelectedServices] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<'map' | 'directions'>('map');
  const [activePharmacy, setActivePharmacy] = useState<Partial<Pharmacy> | null>(null);
  const [trajetDetails, setTrajetDetails] = useState<{distance: string, time: string, steps: RouteStep[]} | null>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
          setUserLocation(loc);
          setMapQuery(`pharmacies near ${loc.lat},${loc.lng}`);
        },
        () => {
          setUserLocation({ lat: 36.8065, lng: 10.1815 }); // Tunis Default
        }
      );
    }
  }, []);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!userLocation) return;

    setIsSearching(true);
    setViewMode('map');
    try {
      let q = searchQuery || "pharmacies";
      if (selectedServices.length > 0) q += ` with ${selectedServices.join(', ')}`;
      const result = await findNearbyPharmacies(userLocation.lat, userLocation.lng, q);
      setAiResults(result.grounding);
      setMapQuery(`${q} near ${userLocation.lat},${userLocation.lng}`);
      setActivePharmacy(null);
      setTrajetDetails(null);
    } catch (error) {
      console.error("Maps search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  const generateMockSteps = (name: string): RouteStep[] => {
    return [
      { instruction: "Head south on your current street", distance: "450m" },
      { instruction: `Turn right towards the direction of ${name}`, distance: "1.2km" },
      { instruction: "Continue straight past the central roundabout", distance: "800m" },
      { instruction: `The pharmacy will be on your left`, distance: "100m" },
    ];
  };

  const handleGetDirections = (pharmacy: Partial<Pharmacy>) => {
    setActivePharmacy(pharmacy);
    setViewMode('directions');

    const dist = (Math.random() * 4 + 0.5).toFixed(1);
    const time = Math.round(parseFloat(dist) * 4);

    setTrajetDetails({ 
      distance: `${dist} km`, 
      time: `${time} min`,
      steps: generateMockSteps(pharmacy.name || 'Pharmacy')
    });

    const destination = pharmacy.address ? `${pharmacy.name}, ${pharmacy.address}` : `${pharmacy.name}`;
    setMapQuery(`from+current+location+to+${destination.replace(/\s+/g, '+')}`);
  };

  const getEmbedUrl = () => {
    const baseUrl = "https://www.google.com/maps";
    if (viewMode === 'directions' && activePharmacy) {
      const dest = activePharmacy.address ? `${activePharmacy.name}, ${activePharmacy.address}` : `${activePharmacy.name}`;
      return `${baseUrl}?saddr=My+Location&daddr=${encodeURIComponent(dest)}&output=embed`;
    }
    return `${baseUrl}?q=${encodeURIComponent(mapQuery)}&output=embed`;
  };

  return (
    <div className="h-full space-y-6 animate-in fade-in duration-500 pb-12">
      <div className="space-y-4">
        <form onSubmit={handleSearch} className="bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <i className="fas fa-search absolute left-6 top-1/2 -translate-y-1/2 text-slate-400"></i>
            <input 
              type="text" 
              placeholder="Search by name, medicine or city..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-700"
            />
          </div>
          <button 
            type="submit"
            disabled={isSearching}
            className="px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50 shadow-lg shadow-blue-100"
          >
            {isSearching ? <i className="fas fa-circle-notch animate-spin"></i> : <i className="fas fa-map-pin"></i>}
            EXPLORE
          </button>
        </form>

        <div className="flex flex-wrap items-center gap-3 px-2">
          {ALL_SERVICES.map(service => (
            <button
              key={service}
              onClick={() => setSelectedServices(prev => prev.includes(service) ? prev.filter(s => s !== service) : [...prev, service])}
              className={`px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-wider transition-all border ${
                selectedServices.includes(service) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-blue-300'
              }`}
            >
              {service}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-[650px]">
        {/* Results / Directions Sidebar */}
        <div className="lg:col-span-4 space-y-4 overflow-y-auto pr-2 custom-scrollbar">
          {viewMode === 'directions' && activePharmacy ? (
            <div className="space-y-4 animate-in slide-in-from-left duration-300">
               <div className="bg-slate-900 text-white p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none">
                    <i className="fas fa-route text-8xl"></i>
                  </div>
                  <button 
                    onClick={() => setViewMode('map')} 
                    className="absolute top-6 right-6 w-8 h-8 flex items-center justify-center bg-white/10 rounded-full hover:bg-white/20 transition"
                  >
                    <i className="fas fa-times text-xs"></i>
                  </button>
                  <h3 className="text-2xl font-black mb-1">{activePharmacy.name}</h3>
                  <p className="text-xs text-slate-400 font-medium mb-6">{activePharmacy.address}</p>

                  <div className="grid grid-cols-2 gap-4 mb-8">
                    <div className="bg-white/5 border border-white/10 p-4 rounded-2xl">
                      <span className="text-[10px] font-black text-slate-500 uppercase block mb-1">Distance</span>
                      <span className="text-xl font-black text-blue-400">{trajetDetails?.distance}</span>
                    </div>
                    <div className="bg-white/5 border border-white/10 p-4 rounded-2xl">
                      <span className="text-[10px] font-black text-slate-500 uppercase block mb-1">Duration</span>
