import React, { useState, useEffect, useCallback } from 'react';
import { User, Medication, UserRole } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PharmacyMap from './components/PharmacyMap';
import HistoryView from './components/HistoryView';
import Auth from './components/Auth';
import NotificationProvider from './components/NotificationProvider';
import InventoryManager from './components/InventoryManager';

const API_BASE = 'http://localhost:5000/api';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(localStorage.getItem('token'));
  const [view, setView] = useState<'dashboard' | 'map' | 'profile' | 'history' | 'inventory'>('dashboard');
  const [medications, setMedications] = useState<Medication[]>([]);

  // Memoized fetch function to avoid re-renders
  const fetchMedications = useCallback(async (userToken: string) => {
    try {
      const res = await fetch(`${API_BASE}/medications`, {
        headers: { 'Authorization': `Bearer ${userToken}` }
      });
      if (!res.ok) throw new Error("Backend offline");
      const data = await res.json();
      setMedications(data);
    } catch (err) {
      const localMeds = localStorage.getItem('medcare_meds');
      if (localMeds) {
        setMedications(JSON.parse(localMeds));
      } else {
        setMedications([]);
      }
    }
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    if (savedUser && token) {
      setUser(JSON.parse(savedUser));
      fetchMedications(token);
    }
  }, [token, fetchMedications]);

  const handleLogin = (u: User, t: string) => {
    setUser(u);
    setToken(t);
    localStorage.setItem('user', JSON.stringify(u));
    localStorage.setItem('token', t);
    fetchMedications(t);
  };

  const handleLogout = () => {
    setUser(null);
    setToken(null);
    localStorage.clear();
  };

  const handleMedicationChange = (update: Medication[] | ((prev: Medication[]) => Medication[])) => {
    setMedications(prev => {
      const updated = typeof update === 'function' ? update(prev) : update;
      localStorage.setItem('medcare_meds', JSON.stringify(updated));
      return updated;
    });
  };

  if (!user || !token) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <NotificationProvider medications={medications}>
      <Layout 
        user={user} 
        currentView={view} 
        onViewChange={setView} 
        onLogout={handleLogout}
      >
        {view === 'dashboard' && (
          <Dashboard 
            user={user} 
            medications={medications} 
            setMedications={handleMedicationChange} 
          />
        )}
        {view === 'map' && <PharmacyMap pharmacies={[]} />}
        {view === 'history' && <HistoryView medications={medications} />}
        {view === 'inventory' && <InventoryManager />}
        {view === 'profile' && (
           <div className="bg-white p-10 md:p-16 rounded-[3.5rem] shadow-sm border border-slate-100 max-w-2xl mx-auto animate-in fade-in zoom-in">
             <div className="flex flex-col items-center gap-6 mb-10">
                <div className="w-32 h-32 rounded-[2.5rem] bg-gradient-to-br from-blue-600 to-indigo-700 flex items-center justify-center text-white text-5xl font-black shadow-2xl shadow-blue-200">
                  {user.name[0]}
                </div>
                <div className="text-center">
                  <h2 className="text-4xl font-black text-slate-900 mb-1">{user.name}</h2>
                  <p className="text-slate-500 font-bold uppercase tracking-widest text-sm">{user.email}</p>
                </div>
             </div>
             <div className="grid grid-cols-2 gap-6 mb-10">
                <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100 flex flex-col items-center">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Role</span>
                  <span className="font-black text-blue-600 text-lg">{user.role}</span>
                </div>
                <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100 flex flex-col items-center">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Treatments</span>
                  <span className="font-black text-slate-700 text-lg">{medications.length}</span>
                </div>
             </div>
             <div className="flex flex-col gap-3">
               <button 
                 onClick={() => setView('dashboard')}
                 className="w-full py-4 bg-slate-900 text-white font-black rounded-2xl hover:bg-slate-800 transition shadow-lg active:scale-95"
               >
                 RETURN TO DASHBOARD
               </button>
               <button 
                 onClick={handleLogout}
                 className="w-full py-4 bg-red-50 text-red-600 font-black rounded-2xl hover:bg-red-100 transition flex items-center justify-center gap-3 active:scale-95"
               >
                 <i className="fas fa-sign-out-alt"></i> SIGN OUT
               </button>
             </div>
           </div>
        )}
      </Layout>
    </NotificationProvider>
  );
};

export default App;

