import React, { useState, useEffect, useCallback } from 'react';
import { User, Medication, UserRole } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import PharmacyMap from './components/PharmacyMap';
import HistoryView from './components/HistoryView';
import Auth from './components/Auth';
import NotificationProvider from './components/NotificationProvider';
import InventoryManager from './components/InventoryManager';

const API_BASE = 'http://localhost:5000/api';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(localStorage.getItem('token'));
  const [view, setView] = useState<'dashboard' | 'map' | 'profile' | 'history' | 'inventory'>('dashboard');
  const [medications, setMedications] = useState<Medication[]>([]);

  const fetchMedications = useCallback(async (userToken: string) => {
    try {
      const res = await fetch(`${API_BASE}/medications`, {
        headers: { 'Authorization': `Bearer ${userToken}` }
      });
      if (!res.ok) throw new Error("Backend unreachable");
      const data = await res.json();
      setMedications(data);
    } catch (err) {
      const localMeds = localStorage.getItem('medcare_meds');
      if (localMeds) {
        setMedications(JSON.parse(localMeds));
      } else {
        setMedications([]);
      }
    }
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    const savedToken = localStorage.getItem('token');

    if (savedUser && savedToken) {
      try {
        const parsedUser = JSON.parse(savedUser);
        setUser(parsedUser);
        setToken(savedToken);
        fetchMedications(savedToken);
      } catch (e) {
        console.error("Auth state corrupted, resetting...");
        localStorage.clear();
      }
    }
  }, [fetchMedications]);

  const handleLogin = (u: User, t: string) => {
    setUser(u);
    setToken(t);
    localStorage.setItem('user', JSON.stringify(u));
    localStorage.setItem('token', t);
    fetchMedications(t);
  };

  const handleLogout = () => {
    setUser(null);
    setToken(null);
    localStorage.clear();
    setView('dashboard');
  };

  const handleMedicationChange = (update: Medication[] | ((prev: Medication[]) => Medication[])) => {
    setMedications(prev => {
      const updated = typeof update === 'function' ? update(prev) : update;
      localStorage.setItem('medcare_meds', JSON.stringify(updated));
      return updated;
    });
  };

  const handleDownloadLogo = () => {
    // Create high-res canvas (1024x1024)
    const canvas = document.createElement('canvas');
    canvas.width = 1024;
    canvas.height = 1024;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // 1. Draw Background Gradient
    const gradient = ctx.createLinearGradient(0, 0, 1024, 1024);
    gradient.addColorStop(0, '#2563eb'); // blue-600
    gradient.addColorStop(1, '#4338ca'); // indigo-700

    // 2. Draw Rounded Square Container
    const padding = 100;
    const size = 1024 - (padding * 2);
    const radius = 220;

    ctx.fillStyle = gradient;
    ctx.beginPath();
    // Path for rounded rectangle
    ctx.moveTo(padding + radius, padding);
    ctx.lineTo(padding + size - radius, padding);
    ctx.quadraticCurveTo(padding + size, padding, padding + size, padding + radius);
    ctx.lineTo(padding + size, padding + size - radius);
    ctx.quadraticCurveTo(padding + size, padding + size, padding + size - radius, padding + size);
    ctx.lineTo(padding + radius, padding + size);
    ctx.quadraticCurveTo(padding, padding + size, padding, padding + size - radius);
    ctx.lineTo(padding, padding + radius);
    ctx.quadraticCurveTo(padding, padding, padding + radius, padding);
    ctx.closePath();
    ctx.fill();

    // 3. Draw Medical Plus Sign (Simplified version of fa-plus-medical)
    ctx.fillStyle = 'white';
    const centerX = 512;
    const centerY = 512;
    const thickness = 140;
    const length = 460;

    // Vertical bar
    ctx.fillRect(centerX - (thickness / 2), centerY - (length / 2), thickness, length);
    // Horizontal bar
    ctx.fillRect(centerX - (length / 2), centerY - (thickness / 2), length, thickness);

    // 4. Export as PNG
    const link = document.createElement('a');
    link.download = 'medcare-alert-logo.png';
    link.href = canvas.toDataURL('image/png');
    link.click();
  };

  if (!user || !token) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <NotificationProvider medications={medications}>
      <Layout 
        user={user} 
        currentView={view} 
        onViewChange={setView} 
        onLogout={handleLogout}
      >
        {view === 'dashboard' && (
          <Dashboard 
            user={user} 
            medications={medications} 
            setMedications={handleMedicationChange} 
          />
        )}
        {view === 'map' && <PharmacyMap pharmacies={[]} />}
        {view === 'history' && <HistoryView medications={medications} />}
        {view === 'inventory' && <InventoryManager />}
        {view === 'profile' && (
           <div className="bg-white p-10 md:p-16 rounded-[3.5rem] shadow-sm border border-slate-100 max-w-2xl mx-auto animate-in fade-in zoom-in duration-500">
             <div className="flex flex-col items-center gap-6 mb-10">
                <div className="w-32 h-32 rounded-[2.5rem] bg-gradient-to-br from-blue-600 to-indigo-700 flex items-center justify-center text-white text-5xl font-black shadow-2xl shadow-blue-200">
                  {user.name[0]}
                </div>
                <div className="text-center">
                  <h2 className="text-4xl font-black text-slate-900 mb-1">{user.name}</h2>
                  <p className="text-slate-500 font-bold uppercase tracking-widest text-sm">{user.email}</p>
                </div>
             </div>
             <div className="grid grid-cols-2 gap-6 mb-10">
                <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100 flex flex-col items-center">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Role</span>
                  <span className="font-black text-blue-600 text-lg">{user.role}</span>
                </div>
                <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100 flex flex-col items-center">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Treatments</span>
                  <span className="font-black text-slate-700 text-lg">{medications.length}</span>
                </div>
             </div>

             <div className="bg-blue-50/50 border border-blue-100 p-8 rounded-[2.5rem] mb-10">
               <h3 className="text-sm font-black text-blue-900 uppercase tracking-widest mb-4 flex items-center gap-2">
                 <i className="fas fa-download"></i> Brand Assets
               </h3>
               <p className="text-slate-500 text-sm mb-6 font-medium">Download the official MedCareAlert+ high-resolution logo for your personal records or devices.</p>
               <button 
                 onClick={handleDownloadLogo}
                 className="w-full py-4 bg-white border-2 border-blue-200 text-blue-600 font-black rounded-2xl hover:bg-blue-600 hover:text-white transition-all shadow-sm flex items-center justify-center gap-3 active:scale-95"
               >
                 <i className="fas fa-file-image"></i> DOWNLOAD LOGO (PNG)
               </button>
             </div>

             <div className="flex flex-col gap-3">
               <button 
                 onClick={() => setView('dashboard')}
                 className="w-full py-4 bg-slate-900 text-white font-black rounded-2xl hover:bg-slate-800 transition shadow-lg active:scale-95"
               >
                 RETURN TO DASHBOARD
               </button>
               <button 
                 onClick={handleLogout}
                 className="w-full py-4 bg-red-50 text-red-600 font-black rounded-2xl hover:bg-red-100 transition flex items-center justify-center gap-3 active:scale-95"
               >
                 <i className="fas fa-sign-out-alt"></i> SIGN OUT
               </button>
             </div>
           </div>
        )}
      </Layout>
    </NotificationProvider>
  );
};

export default App;

import React, { useState } from 'react';

